// 자동 생성 — 종목↔free-exercise-db 미디어 매핑(빌드 스크립트). 직접 수정 금지. @plm SRS-032
// s=시작 이미지 경로, e=끝 이미지 경로(free-exercise-db exercises/<경로>), k=한국어 스텝, en=영문 스텝.

export interface RawMedia {
  s: string;
  e: string;
  k: string[];
  en: string[];
}

// 키=종목 한국어명(nameKo). 129종목(무매칭 7종 제외). @plm SRS-032
export const RAW_MEDIA: Record<string, RawMedia> = {
  "바벨 벤치프레스": { s: "Barbell_Bench_Press_-_Medium_Grip/0.jpg", e: "Barbell_Bench_Press_-_Medium_Grip/1.jpg", k: ["플랫 벤치에 등을 대고 눕는다. 미디엄 그립(동작 중간 지점에서 아래팔과 위팔이 90도를 이루는 너비)으로 랙에서 바를 들어 올려 팔을 편 채 몸 위로 곧게 세운다. 이것이 시작 자세다.", "시작 자세에서 숨을 들이마시며 바가 가슴 중앙에 닿을 때까지 천천히 내린다.", "잠깐 멈춘 뒤 숨을 내쉬며 바를 시작 자세로 밀어 올린다. 가슴 근육으로 바를 밀어 올리는 데 집중한다. 동작 맨 위에서 팔을 펴고 가슴을 수축시켜 1초간 유지한 뒤 다시 천천히 내린다. 팁: 이상적으로는 내리는 시간이 올리는 시간의 약 두 배가 되도록 한다.", "정해진 반복 횟수만큼 동작을 반복한다.", "끝나면 바를 랙에 다시 걸어 둔다."], en: ["Lie back on a flat bench. Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "From the starting position, breathe in and begin coming down slowly until the bar touches your middle chest.", "After a brief pause, push the bar back to the starting position as you breathe out. Focus on pushing the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position at the top of the motion, hold for a second and then start coming down slowly again. Tip: Ideally, lowering the weight should take about twice as long as raising it.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."] },
  "인클라인 프레스": { s: "Barbell_Incline_Bench_Press_-_Medium_Grip/0.jpg", e: "Barbell_Incline_Bench_Press_-_Medium_Grip/1.jpg", k: ["인클라인 벤치에 등을 대고 눕는다. 미디엄 그립(동작 중간 지점에서 아래팔과 위팔이 90도를 이루는 너비)으로 랙에서 바를 들어 올려 팔을 편 채 몸 위로 곧게 세운다. 이것이 시작 자세다.", "숨을 들이마시며 바가 윗가슴에 닿는 느낌이 들 때까지 천천히 내린다.", "1초간 멈춘 뒤 숨을 내쉬며 가슴 근육으로 바를 밀어 시작 자세로 되돌린다. 수축 자세에서 팔을 펴고 가슴을 쥐어짜듯 수축시켜 1초간 유지한 뒤 다시 천천히 내린다. 팁: 내리는 시간이 올리는 시간의 최소 두 배가 되도록 한다.", "정해진 반복 횟수만큼 동작을 반복한다.", "끝나면 바를 랙에 다시 걸어 둔다."], en: ["Lie back on an incline bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "As you breathe in, come down slowly until you feel the bar on you upper chest.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly again. Tip: it should take at least twice as long to go down than to come up.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."] },
  "디클라인 바벨 프레스": { s: "Decline_Barbell_Bench_Press/0.jpg", e: "Decline_Barbell_Bench_Press/1.jpg", k: ["디클라인 벤치 끝에 다리를 고정하고 천천히 벤치에 눕는다.", "미디엄 그립(동작 중간 지점에서 아래팔과 위팔이 90도를 이루는 너비)으로 랙에서 바를 들어 올려 팔을 편 채 몸 위로 곧게 세운다. 팔은 바닥과 수직이어야 한다. 이것이 시작 자세다. 팁: 회전근개를 보호하려면 보조자가 랙에서 바벨을 들어 올리는 것을 도와주는 것이 가장 좋다.", "숨을 들이마시며 바가 아랫가슴에 닿는 느낌이 들 때까지 천천히 내린다.", "1초간 멈춘 뒤 숨을 내쉬며 가슴 근육으로 바를 밀어 시작 자세로 되돌린다. 수축 자세에서 팔을 펴고 가슴을 수축시켜 1초간 유지한 뒤 다시 천천히 내린다. 팁: 내리는 시간이 올리는 시간의 최소 두 배가 되도록 한다.", "정해진 반복 횟수만큼 동작을 반복한다.", "끝나면 바를 랙에 다시 걸어 둔다."], en: ["Secure your legs at the end of the decline bench and slowly lay down on the bench.", "Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.", "As you breathe in, come down slowly until you feel the bar on your lower chest.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."] },
  "덤벨 벤치프레스": { s: "Dumbbell_Bench_Press/0.jpg", e: "Dumbbell_Bench_Press/1.jpg", k: ["플랫 벤치에 누워 양손에 덤벨을 하나씩 들고 허벅지 위에 올려 둔다. 손바닥은 서로 마주 보게 한다.", "허벅지의 반동을 이용해 덤벨을 하나씩 들어 올려 어깨너비로 몸 앞에 든다.", "어깨너비에 오면 손목을 앞으로 돌려 손바닥이 앞쪽(몸 반대편)을 향하게 한다. 덤벨은 가슴 양옆에 위치하고, 위팔과 아래팔이 90도를 이루어야 한다. 항상 덤벨을 완전히 통제한다. 이것이 시작 자세다.", "숨을 내쉬며 가슴 근육으로 덤벨을 밀어 올린다. 동작 맨 위에서 팔을 펴고 가슴을 수축시켜 1초간 유지한 뒤 천천히 내린다. 팁: 이상적으로는 내리는 시간이 올리는 시간의 약 두 배가 되도록 한다.", "트레이닝 프로그램에 정해진 반복 횟수만큼 동작을 반복한다."], en: ["Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other.", "Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.", "Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. The dumbbells should be just to the sides of your chest, with your upper arm and forearm creating a 90 degree angle. Be sure to maintain full control of the dumbbells at all times. This will be your starting position.", "Then, as you breathe out, use your chest to push the dumbbells up. Lock your arms at the top of the lift and squeeze your chest, hold for a second and then begin coming down slowly. Tip: Ideally, lowering the weight should take about twice as long as raising it.", "Repeat the movement for the prescribed amount of repetitions of your training program."] },
  "디클라인 덤벨 프레스": { s: "Decline_Dumbbell_Bench_Press/0.jpg", e: "Decline_Dumbbell_Bench_Press/1.jpg", k: ["디클라인 벤치 끝에 다리를 고정하고 양손에 덤벨을 하나씩 들어 허벅지 위에 올린 채 눕는다. 손바닥은 서로 마주 보게 한다.", "누운 뒤 덤벨을 어깨너비로 몸 앞에 위치시킨다.", "어깨너비에 오면 손목을 앞으로 돌려 손바닥이 앞쪽(몸 반대편)을 향하게 한다. 이것이 시작 자세다.", "숨을 내쉬며 덤벨을 천천히 양옆으로 내린다. 항상 덤벨을 완전히 통제한다. 팁: 동작 내내 아래팔은 항상 바닥과 수직을 유지해야 한다.", "숨을 내쉬며 가슴 근육으로 덤벨을 밀어 올린다. 수축 자세에서 팔을 펴고 가슴을 쥐어짜듯 수축시켜 1초간 유지한 뒤 천천히 내린다. 팁: 내리는 시간이 올리는 시간의 최소 두 배가 되도록 한다.", "트레이닝 프로그램에 정해진 반복 횟수만큼 동작을 반복한다."], en: ["Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.", "Once you are laying down, move the dumbbells in front of you at shoulder width.", "Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.", "Bring down the weights slowly to your side as you breathe out. Keep full control of the dumbbells at all times. Tip: Throughout the motion, the forearms should always be perpendicular to the floor.", "As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up..", "Repeat the movement for the prescribed amount of repetitions of your training program."] },
  "덤벨 플라이": { s: "Dumbbell_Flyes/0.jpg", e: "Dumbbell_Flyes/1.jpg", k: ["플랫 벤치에 누워 양손에 덤벨을 하나씩 들어 허벅지 위에 올린다. 손바닥은 서로 마주 보게 한다.", "허벅지의 반동을 이용해 덤벨을 하나씩 들어 올려 손바닥이 서로 마주 본 채 어깨너비로 몸 앞에 든다. 프레스하듯 덤벨을 밀어 올리되 팔을 완전히 펴기 직전에 멈추고 유지한다. 이것이 시작 자세다.", "이두근 힘줄에 부담이 가지 않도록 팔꿈치를 살짝 구부린 상태에서, 가슴이 늘어나는 느낌이 들 때까지 양팔을 넓은 호를 그리며 양옆으로 내린다. 이 동작을 하는 동안 숨을 들이마신다. 팁: 동작 내내 팔은 고정된 상태를 유지하고, 움직임은 오직 어깨 관절에서만 일어나야 한다.", "가슴 근육을 쥐어짜듯 수축시키고 숨을 내쉬며 양팔을 시작 자세로 되돌린다. 팁: 내릴 때와 같은 호의 궤적을 사용한다.", "수축 자세에서 1초간 유지하고 정해진 반복 횟수만큼 동작을 반복한다."], en: ["Lie down on a flat bench with a dumbbell on each hand resting on top of your thighs. The palms of your hand will be facing each other.", "Then using your thighs to help raise the dumbbells, lift the dumbbells one at a time so you can hold them in front of you at shoulder width with the palms of your hands facing each other. Raise the dumbbells up like you're pressing them, but stop and hold just before you lock out. This will be your starting position.", "With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.", "Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.", "Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."] },
  "인클라인 덤벨 플라이": { s: "Incline_Dumbbell_Flyes/0.jpg", e: "Incline_Dumbbell_Flyes/1.jpg", k: ["양손에 덤벨을 하나씩 들고 각도가 30도를 넘지 않게 세팅한 인클라인 벤치에 눕는다.", "팔꿈치를 살짝 구부린 채 양팔을 몸 위로 뻗는다.", "이제 손목을 돌려 손바닥이 자신을 향하게 한다. 팁: 새끼손가락이 서로 나란히 오도록 한다. 이것이 시작 자세다.", "숨을 들이마시며 팔을 뻗은 상태를 유지한 채 천천히 양옆으로 내리고, 손바닥이 서로 마주 볼 때까지 손목을 돌린다. 팁: 동작이 끝나면 팔은 몸 옆에 오고 손바닥은 천장을 향한다.", "숨을 내쉬며 동작을 반대로 하여 덤벨을 시작 자세로 되돌리고, 새끼손가락이 다시 나란히 오도록 손을 돌린다. 팁: 움직임은 오직 어깨 관절과 손목에서만 일어난다는 점을 명심한다. 팔꿈치 관절에서는 어떤 움직임도 일어나지 않는다.", "권장 반복 횟수만큼 반복한다."], en: ["Hold a dumbbell on each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.", "Extend your arms above you with a slight bend at the elbows.", "Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.", "As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.", "As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.", "Repeat for the recommended amount of repetitions."] },
  "케이블 크로스오버": { s: "Cable_Crossover/0.jpg", e: "Cable_Crossover/1.jpg", k: ["시작 자세를 잡기 위해 도르래를 높은 위치(머리 위)에 두고 사용할 무게를 선택한 뒤 양손에 도르래 손잡이를 잡는다.", "양쪽 도르래 사이의 가상의 직선 앞으로 한 걸음 나가면서 양팔을 몸 앞으로 모은다. 상체는 허리에서 앞으로 살짝 숙인다. 이것이 시작 자세다.", "이두근 힘줄에 부담이 가지 않도록 팔꿈치를 살짝 구부린 상태에서, 가슴이 늘어나는 느낌이 들 때까지 양팔을 넓은 호를 그리며 양옆으로 뻗는다. 이 동작을 하는 동안 숨을 들이마신다. 팁: 동작 내내 팔과 상체는 고정된 상태를 유지하고, 움직임은 오직 어깨 관절에서만 일어나야 한다.", "숨을 내쉬며 양팔을 시작 자세로 되돌린다. 내릴 때와 같은 호의 궤적을 사용한다.", "시작 자세에서 1초간 유지하고 정해진 반복 횟수만큼 동작을 반복한다."], en: ["To get yourself into the starting position, place the pulleys on a high position (above your head), select the resistance to be used and hold the pulleys in each hand.", "Step forward in front of an imaginary straight line between both pulleys while pulling your arms together in front of you. Your torso should have a small forward bend from the waist. This will be your starting position.", "With a slight bend on your elbows in order to prevent stress at the biceps tendon, extend your arms to the side (straight out at both sides) in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms and torso should remain stationary; the movement should only occur at the shoulder joint.", "Return your arms back to the starting position as you breathe out. Make sure to use the same arc of motion used to lower the weights.", "Hold for a second at the starting position and repeat the movement for the prescribed amount of repetitions."] },
  "로우 케이블 플라이": { s: "Low_Cable_Crossover/0.jpg", e: "Low_Cable_Crossover/1.jpg", k: ["시작 자세로 들어가기 위해 도르래를 낮은 위치에 두고 사용할 무게를 선택한 뒤 양손에 손잡이를 하나씩 잡는다.", "앞으로 한 걸음 나가 도르래에 장력을 준다. 손바닥은 앞을 향하고, 손은 허리 아래에 두며, 팔은 편 상태다. 이것이 시작 자세다.", "팔을 살짝 구부린 채 양손을 위쪽과 몸 중심선 방향으로 끌어 올린다. 손바닥이 위를 향한 채 양손이 가슴 앞에서 모이게 한다.", "잠깐 멈춘 뒤 양팔을 시작 자세로 되돌린다."], en: ["To move into the starting position, place the pulleys at the low position, select the resistance to be used and grasp a handle in each hand.", "Step forward, gaining tension in the pulleys. Your palms should be facing forward, hands below the waist, and your arms straight. This will be your starting position.", "With a slight bend in your arms, draw your hands upward and toward the midline of your body. Your hands should come together in front of your chest, palms facing up.", "Return your arms back to the starting position after a brief pause."] },
  "펙 덱 플라이": { s: "Butterfly/0.jpg", e: "Butterfly/1.jpg", k: ["등을 패드에 밀착시킨 채 머신에 앉는다.", "손잡이를 잡는다. 팁: 위팔이 바닥과 평행이 되도록 한다. 그에 맞게 머신을 조절한다. 이것이 시작 자세다.", "가슴을 중앙으로 쥐어짜듯 수축시키며 손잡이를 천천히 모은다. 이 동작을 하는 동안 숨을 내쉬고 수축을 1초간 유지한다.", "숨을 들이마시며 가슴 근육이 완전히 늘어날 때까지 천천히 시작 자세로 되돌린다.", "권장 반복 횟수만큼 반복한다."], en: ["Sit on the machine with your back flat on the pad.", "Take hold of the handles. Tip: Your upper arms should be positioned parallel to the floor; adjust the machine accordingly. This will be your starting position.", "Push the handles together slowly as you squeeze your chest in the middle. Breathe out during this part of the motion and hold the contraction for a second.", "Return back to the starting position slowly as you inhale until your chest muscles are fully stretched.", "Repeat for the recommended amount of repetitions."] },
  "체스트 프레스 머신": { s: "Leverage_Chest_Press/0.jpg", e: "Leverage_Chest_Press/1.jpg", k: ["핀에 적절한 무게를 걸고 자신의 키에 맞게 좌석을 조절한다. 동작 시작 시 손잡이는 가슴 아래쪽이나 중앙 근처에 와야 한다.", "가슴과 머리를 세우고 견갑골을 뒤로 모은다. 이것이 시작 자세다.", "팔꿈치를 펴며 손잡이를 앞으로 민다.", "맨 위에서 잠깐 멈춘 뒤 시작 자세 바로 위까지 무게를 되돌리되, 세트가 끝날 때까지 무게를 완전히 스톱에 내려놓지 않아 근육에 긴장을 유지한다."], en: ["Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom or middle of the pectorals at the beginning of the motion.", "Your chest and head should be up and your shoulder blades retracted. This will be your starting position.", "Press the handles forward by extending through the elbow.", "After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete."] },
  "스미스 벤치프레스": { s: "Smith_Machine_Bench_Press/0.jpg", e: "Smith_Machine_Bench_Press/1.jpg", k: ["스미스 머신 아래에 플랫 벤치를 놓는다. 누웠을 때 팔을 거의 다 편 상태에서 닿을 수 있는 높이에 바벨을 위치시킨다. 필요한 무게를 선택한 뒤 플랫 벤치에 눕는다. 어깨너비보다 넓은 오버핸드 그립으로 랙에서 바를 풀어 팔을 편 채 몸 위로 곧게 세운다. 이것이 시작 자세다.", "숨을 들이마시며 바가 가슴 중앙에 닿는 느낌이 들 때까지 천천히 내린다.", "1초간 멈춘 뒤 숨을 내쉬며 가슴 근육으로 바를 밀어 시작 자세로 되돌린다. 수축 자세에서 팔을 펴고 1초간 유지한 뒤 다시 천천히 내린다. 팁: 내리는 시간이 올리는 시간의 최소 두 배가 되도록 한다.", "정해진 반복 횟수만큼 동작을 반복한다.", "끝나면 바를 랙에 다시 잠근다."], en: ["Place a flat bench underneath the smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "As you breathe in, come down slowly until you feel the bar on your middle chest.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, lock the bar back in the rack."] },
  "딥스": { s: "Dips_-_Chest_Version/0.jpg", e: "Dips_-_Chest_Version/1.jpg", k: ["이 운동을 하려면 평행봉이 필요하다. 시작 자세를 잡기 위해 팔을 편 채(팔을 곧게 편 상태) 바 위로 몸을 지탱한다.", "숨을 들이마시며 상체를 약 30도 정도 앞으로 기울이고 팔꿈치를 살짝 벌린 채, 가슴이 살짝 늘어나는 느낌이 들 때까지 몸을 천천히 내린다.", "늘어나는 느낌이 들면 숨을 내쉬며 가슴 힘으로 몸을 시작 자세로 되돌린다. 팁: 동작 맨 위에서 가슴을 1초간 수축시키는 것을 잊지 않는다.", "정해진 반복 횟수만큼 동작을 반복한다."], en: ["For this exercise you will need access to parallel bars. To get yourself into the starting position, hold your body at arms length (arms locked) above the bars.", "While breathing in, lower yourself slowly with your torso leaning forward around 30 degrees or so and your elbows flared out slightly until you feel a slight stretch in the chest.", "Once you feel the stretch, use your chest to bring your body back to the starting position as you breathe out. Tip: Remember to squeeze the chest at the top of the movement for a second.", "Repeat the movement for the prescribed amount of repetitions."] },
  "푸시업": { s: "Pushups/0.jpg", e: "Pushups/1.jpg", k: ["바닥에 엎드려 양손을 약 90cm 정도 벌리고 팔을 편 채 상체를 지탱한다.", "숨을 들이마시며 가슴이 바닥에 거의 닿을 때까지 몸을 내린다.", "숨을 내쉬며 가슴을 수축시켜 상체를 시작 자세로 밀어 올린다.", "맨 위 수축 자세에서 잠깐 멈춘 뒤 필요한 반복 횟수만큼 다시 몸을 내리기 시작한다."], en: ["Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length.", "Next, lower yourself downward until your chest almost touches the floor as you inhale.", "Now breathe out and press your upper body back up to the starting position while squeezing your chest.", "After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed."] },
  "인클라인 푸시업": { s: "Incline_Push-Up/0.jpg", e: "Incline_Push-Up/1.jpg", k: ["벤치나 튼튼한 높은 받침대를 마주 보고 선다. 양손을 벤치나 받침대 가장자리에 어깨너비보다 살짝 넓게 올린다.", "팔과 몸을 곧게 편 채 발 앞부분을 벤치나 받침대에서 뒤로 위치시킨다. 팔은 몸과 수직이 되어야 한다. 몸을 곧게 유지하며 팔을 구부려 가슴을 박스나 받침대 가장자리로 내린다.", "팔이 펴질 때까지 몸을 밀어 올린다. 반복한다."], en: ["Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width.", "Position forefoot back from bench or platform with arms and body straight. Arms should be perpendicular to body. Keeping body straight, lower chest to edge of box or platform by bending arms.", "Push body up until arms are extended. Repeat."] },
  "데드리프트": { s: "Barbell_Deadlift/0.jpg", e: "Barbell_Deadlift/1.jpg", k: ["무게가 실린 바벨 앞에 선다.", "등을 최대한 곧게 편 채 무릎을 구부리고 상체를 앞으로 숙여 미디엄(어깨너비) 오버핸드 그립으로 바를 잡는다. 이것이 운동의 시작 자세다. 팁: 이 그립으로 바를 잡기 어렵다면 그립을 교차(얼터네이트 그립)하거나 손목 스트랩을 사용한다.", "바를 잡은 채 다리로 밀며 동시에 숨을 내쉬면서 상체를 바로 세워 리프트를 시작한다. 선 자세에서 가슴을 내밀고 견갑골을 뒤로 모아 등을 수축시킨다. 군인이 차렷 자세로 서 있을 때의 모습을 떠올린다.", "등을 곧게 편 채 무릎을 구부리며 동시에 허리에서 상체를 앞으로 기울여 시작 자세로 돌아간다. 바의 무게가 바닥에 닿으면 시작 자세로 돌아온 것이며 다음 반복을 수행할 준비가 된다.", "프로그램에 정해진 반복 횟수만큼 수행한다."], en: ["Stand in front of a loaded barbell.", "While keeping the back as straight as possible, bend your knees, bend forward and grasp the bar using a medium (shoulder width) overhand grip. This will be the starting position of the exercise. Tip: If it is difficult to hold on to the bar with this grip, alternate your grip or use wrist straps.", "While holding the bar, start the lift by pushing with your legs while simultaneously getting your torso to the upright position as you breathe out. In the upright position, stick your chest out and contract the back by bringing the shoulder blades back. Think of how the soldiers in the military look when they are in standing in attention.", "Go back to the starting position by bending at the knees while simultaneously leaning the torso forward at the waist while keeping the back straight. When the weights on the bar touch the floor you are back at the starting position and ready to perform another repetition.", "Perform the amount of repetitions prescribed in the program."] },
  "스모 데드리프트": { s: "Sumo_Deadlift/0.jpg", e: "Sumo_Deadlift/1.jpg", k: ["바를 바닥에 놓고 무게를 싣는 것으로 시작한다. 바가 양발 중앙을 지나도록 바에 다가선다. 발은 아주 넓게, 칼라 가까이에 둔다. 엉덩이를 접어 바를 잡는다. 팔은 어깨 바로 아래, 다리 안쪽에 두고, 오버핸드 그립, 얼터네이트 그립, 또는 훅 그립을 사용할 수 있다. 어깨의 힘을 빼면 사실상 팔이 길어지는 효과가 있다.", "숨을 들이마신 뒤 엉덩이를 낮추고 머리는 앞을 보며 가슴을 세운다. 발을 양옆으로 벌리듯 바닥을 밀며, 체중은 발의 뒤쪽 절반에 싣는다. 엉덩이와 무릎을 편다.", "바가 무릎을 지날 때 뒤로 젖히며 엉덩이를 바 쪽으로 밀어 넣고 견갑골을 모은다.", "엉덩이를 접고 내려가는 동안 무게를 통제하며 바를 바닥으로 되돌린다."], en: ["Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.", "Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.", "As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.", "Return the weight to the ground by bending at the hips and controlling the weight on the way down."] },
  "랙 풀": { s: "Rack_Pulls/0.jpg", e: "Rack_Pulls/1.jpg", k: ["파워랙에서 바를 핀 위에 올려 세팅한다. 핀은 원하는 지점(무릎 바로 아래, 바로 위, 또는 허벅지 중간 위치)에 맞춘다. 올바른 데드리프트 자세로 바 앞에 위치한다. 발은 엉덩이 아래에, 그립은 어깨너비로, 등은 아치를 만들고, 엉덩이를 뒤로 빼 햄스트링을 활성화한다. 무게가 대개 무겁기 때문에 얼터네이트 그립, 훅 그립을 쓰거나 스트랩으로 무게를 잡는 데 도움을 받을 수 있다.", "머리는 앞을 본 채 엉덩이와 무릎을 펴며 락아웃될 때까지 무게를 위로, 뒤로 끌어 올린다. 동작을 마무리하면서 어깨를 뒤로 당기는 것을 잊지 않는다.", "무게를 핀으로 되돌리고 반복한다."], en: ["Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.", "With your head looking forward, extend through the hips and knees, pulling the weight up and back until lockout. Be sure to pull your shoulders back as you complete the movement.", "Return the weight to the pins and repeat."] },
  "바벨 로우": { s: "Bent_Over_Barbell_Row/0.jpg", e: "Bent_Over_Barbell_Row/1.jpg", k: ["오버핸드 그립(손바닥이 아래를 향함)으로 바벨을 잡고 무릎을 살짝 구부린 뒤 등을 곧게 편 채 허리에서 상체를 앞으로 숙여 바닥과 거의 평행이 될 때까지 기울인다. 팁: 머리를 든 상태를 유지한다. 팔이 바닥과 상체에 수직으로 늘어뜨려진 채 바벨이 몸 바로 앞에 매달려야 한다. 이것이 시작 자세다.", "이제 상체를 고정한 채 숨을 내쉬며 바벨을 몸 쪽으로 들어 올린다. 팔꿈치를 몸에 가깝게 유지하고 아래팔은 무게를 잡는 역할만 한다. 맨 위 수축 자세에서 등 근육을 쥐어짜듯 수축시키고 잠깐 멈춘다.", "숨을 들이마시며 바벨을 천천히 시작 자세로 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["Holding a barbell with a pronated grip (palms facing down), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.", "Now, while keeping the torso stationary, breathe out and lift the barbell to you. Keep the elbows close to the body and only use the forearms to hold the weight. At the top contracted position, squeeze the back muscles and hold for a brief pause.", "Then inhale and slowly lower the barbell back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "티바 로우": { s: "T-Bar_Row_with_Handle/0.jpg", e: "T-Bar_Row_with_Handle/1.jpg", k: ["바를 랜드마인이나 코너에 고정해 움직이지 않게 한다. 바 끝쪽에 적절한 무게를 싣는다.", "바 위에 서서 더블 D 로우 핸들을 칼라 옆 바 둘레에 건다. 엉덩이와 다리를 사용해 선 자세로 일어선다.", "엉덩이를 뒤로 빼고 가슴을 세운 채 다리를 넓게 벌린다. 팔은 편 상태여야 한다. 이것이 시작 자세다.", "견갑골을 모으고 팔꿈치를 구부려 무게를 윗배 쪽으로 당긴다. 무게를 반동으로 튕기거나 반칙 동작을 하지 않는다.", "잠깐 멈춘 뒤 시작 자세로 되돌린다."], en: ["Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.", "Stand over the bar, and position a Double D row handle around the bar next to the collar. Using your hips and legs, rise to a standing position.", "Assume a wide stance with your hips back and your chest up. Your arms should be extended. This will be your starting position.", "Pull the weight to your upper abdomen by retracting the shoulder blades and flexing the elbows. Do not jerk the weight or cheat during the movement.", "After a brief pause, return to the starting position."] },
  "덤벨 로우": { s: "One-Arm_Dumbbell_Row/0.jpg", e: "One-Arm_Dumbbell_Row/1.jpg", k: ["플랫 벤치를 골라 양옆에 덤벨을 하나씩 놓는다.", "오른쪽 다리를 벤치 끝에 올리고 상체가 바닥과 평행이 될 때까지 허리에서 앞으로 숙인 뒤 오른손을 벤치 반대쪽 끝에 짚어 지탱한다.", "왼손으로 바닥의 덤벨을 잡고 허리를 곧게 편 채 무게를 든다. 손바닥은 상체를 향해야 한다. 이것이 시작 자세다.", "위팔을 몸 옆에 가깝게 유지하고 상체를 고정한 채 무게를 가슴 옆까지 곧게 들어 올린다. 이 동작을 하는 동안 숨을 내쉰다. 팁: 완전히 수축된 지점에 도달하면 등 근육을 쥐어짜듯 수축시키는 데 집중한다. 또한 힘은 팔이 아니라 등 근육으로 내야 한다. 상체는 고정된 상태를 유지하고 팔만 움직여야 한다. 아래팔은 덤벨을 잡는 것 외에 다른 일을 하지 않으므로 아래팔로 덤벨을 당기려 하지 않는다.", "무게를 시작 자세로 곧게 내린다. 이 동작을 하는 동안 숨을 들이마신다.", "정해진 반복 횟수만큼 동작을 반복한다.", "반대쪽으로 바꿔 다른 팔로 다시 반복한다."], en: ["Choose a flat bench and place a dumbbell on each side of it.", "Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.", "Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position.", "Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms.", "Lower the resistance straight down to the starting position. Breathe in as you perform this step.", "Repeat the movement for the specified amount of repetitions.", "Switch sides and repeat again with the other arm."] },
  "시티드 케이블 로우": { s: "Seated_Cable_Rows/0.jpg", e: "Seated_Cable_Rows/1.jpg", k: ["이 운동을 하려면 V바가 달린 로우 풀리 로우 머신이 필요하다. 참고: V바는 손바닥이 서로 마주 보는 중립 그립을 가능하게 한다. 시작 자세를 잡기 위해 먼저 머신에 앉아 무릎을 살짝 구부린 채(완전히 펴지 않음) 앞쪽 발판이나 크로스바에 발을 올린다.", "등의 자연스러운 정렬을 유지한 채 상체를 숙여 V바 손잡이를 잡는다.", "팔을 편 채 상체가 다리와 90도를 이룰 때까지 뒤로 당긴다. 등은 살짝 아치를 만들고 가슴은 내민다. 바를 몸 앞에 든 상태에서 광배근이 시원하게 늘어나는 느낌이 들어야 한다. 이것이 운동의 시작 자세다.", "상체를 고정한 채 팔을 몸에 가깝게 유지하며 손잡이를 복근에 닿을 때까지 상체 쪽으로 당긴다. 이 동작을 하는 동안 숨을 내쉰다. 이때 등 근육을 강하게 쥐어짜듯 수축시켜야 한다. 그 수축을 1초간 유지하고 숨을 들이마시며 천천히 원래 자세로 돌아간다.", "권장 반복 횟수만큼 반복한다."], en: ["For this exercise you will need access to a low pulley row machine with a V-bar. Note: The V-bar will enable you to have a neutral grip where the palms of your hands face each other. To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.", "Lean over as you keep the natural alignment of your back and grab the V-bar handles.", "With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.", "Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.", "Repeat for the recommended amount of repetitions."] },
  "랫 풀다운": { s: "Wide-Grip_Lat_Pulldown/0.jpg", e: "Wide-Grip_Lat_Pulldown/1.jpg", k: ["위쪽 도르래에 와이드 바가 달린 풀다운 머신에 앉는다. 머신의 무릎 패드를 자신의 키에 맞게 조절한다. 이 패드는 바에 걸린 무게에 의해 몸이 위로 들리는 것을 막아 준다.", "정해진 그립으로 손바닥이 앞을 향하게 바를 잡는다. 그립 참고: 와이드 그립은 어깨너비보다 넓게, 미디엄 그립은 어깨너비와 같게, 클로즈 그립은 어깨너비보다 좁게 손을 벌린다.", "선택한 그립 너비로 바를 잡고 양팔을 몸 앞으로 편 상태에서, 상체를 약 30도 정도 뒤로 젖히며 허리에 커브를 만들고 가슴을 내민다. 이것이 시작 자세다.", "숨을 내쉬며 어깨와 위팔을 아래로, 뒤로 당겨 바가 윗가슴에 닿을 때까지 내린다. 팁: 완전히 수축된 지점에 도달하면 등 근육을 쥐어짜듯 수축시키는 데 집중한다. 상체는 고정된 상태를 유지하고 팔만 움직여야 한다. 아래팔은 바를 잡는 것 외에 다른 일을 하지 않으므로 아래팔로 바를 당기려 하지 않는다.", "수축 자세에서 견갑골을 모은 채 1초간 유지한 뒤, 팔이 완전히 펴지고 광배근이 완전히 늘어날 때까지 바를 천천히 시작 자세로 올린다. 이 동작을 하는 동안 숨을 들이마신다.", "정해진 반복 횟수만큼 이 동작을 반복한다."], en: ["Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.", "Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.", "As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.", "As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the bar; therefore do not try to pull down the bar using the forearms.", "After a second at the contracted position squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.", "Repeat this motion for the prescribed amount of repetitions."] },
  "클로즈그립 풀다운": { s: "Close-Grip_Front_Lat_Pulldown/0.jpg", e: "Close-Grip_Front_Lat_Pulldown/1.jpg", k: ["위쪽 도르래에 와이드 바가 달린 풀다운 머신에 앉는다. 머신의 무릎 패드를 자신의 키에 맞게 조절한다. 이 패드는 바에 걸린 무게에 의해 몸이 위로 들리는 것을 막아 준다.", "정해진 그립으로 손바닥이 앞을 향하게 바를 잡는다. 그립 참고: 와이드 그립은 어깨너비보다 넓게, 미디엄 그립은 어깨너비와 같게, 클로즈 그립은 어깨너비보다 좁게 손을 벌린다.", "선택한 그립 너비로 바를 잡고 양팔을 몸 앞으로 편 상태에서, 상체를 약 30도 정도 뒤로 젖히며 허리에 커브를 만들고 가슴을 내민다. 이것이 시작 자세다.", "숨을 내쉬며 어깨와 위팔을 아래로, 뒤로 당겨 바가 윗가슴에 닿을 때까지 내린다. 팁: 완전히 수축된 지점에 도달하면 등 근육을 쥐어짜듯 수축시키는 데 집중한다. 상체는 고정된 상태를 유지한다(팔만 움직여야 한다). 아래팔은 바를 잡는 것 외에 다른 일을 하지 않으므로 아래팔로 바를 당기려 하지 않는다.", "수축 자세에서 견갑골을 모은 채 1초간 유지한 뒤, 팔이 완전히 펴지고 광배근이 완전히 늘어날 때까지 바를 천천히 시작 자세로 올린다. 이 동작을 하는 동안 숨을 들이마신다.", "정해진 반복 횟수만큼 이 동작을 반복한다."], en: ["Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.", "Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.", "As you have both arms extended in front of you - while holding the bar at the chosen grip width - bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.", "As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary (only the arms should move). The forearms should do no other work except for holding the bar; therefore do not try to pull the bar down using the forearms.", "After a second in the contracted position, while squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.", "6. Repeat this motion for the prescribed amount of repetitions."] },
  "스트레이트암 풀다운": { s: "Straight-Arm_Pulldown/0.jpg", e: "Straight-Arm_Pulldown/1.jpg", k: ["풀다운 머신의 위쪽 도르래에서 와이드 바를 잡는 것으로 시작하며, 어깨너비보다 넓은 오버핸드 그립(손바닥이 아래를 향함)을 사용한다. 60cm 정도 뒤로 물러선다.", "팔을 몸 앞으로 완전히 편 채 팔꿈치를 살짝 구부리고, 상체를 허리에서 약 30도 앞으로 숙인다. 팔이 완전히 펴지지 않으면 펴질 때까지 조금 더 뒤로 물러서야 한다. 팔이 완전히 펴지고 상체가 허리에서 살짝 숙여지면 광배근에 힘을 준 뒤 시작할 준비가 된다.", "팔을 편 상태를 유지한 채 광배근을 수축시켜 손이 허벅지 옆에 올 때까지 바를 아래로 당긴다. 이 동작을 하는 동안 숨을 내쉰다.", "팔을 편 상태를 유지한 채 숨을 들이마시며 시작 자세로 돌아간다.", "권장 반복 횟수만큼 반복한다."], en: ["You will start by grabbing the wide bar from the top pulley of a pulldown machine and using a wider than shoulder-width pronated (palms down) grip. Step backwards two feet or so.", "Bend your torso forward at the waist by around 30-degrees with your arms fully extended in front of you and a slight bend at the elbows. If your arms are not fully extended then you need to step a bit more backwards until they are. Once your arms are fully extended and your torso is slightly bent at the waist, tighten the lats and then you are ready to begin.", "While keeping the arms straight, pull the bar down by contracting the lats until your hands are next to the side of the thighs. Breathe out as you perform this step.", "While keeping the arms straight, go back to the starting position while breathing in.", "Repeat for the recommended amount of repetitions."] },
  "풀업": { s: "Pullups/0.jpg", e: "Pullups/1.jpg", k: ["정해진 그립으로 손바닥이 앞을 향하게 풀업 바를 잡는다. 그립 참고: 와이드 그립은 어깨너비보다 넓게, 미디엄 그립은 어깨너비와 같게, 클로즈 그립은 어깨너비보다 좁게 손을 벌린다.", "선택한 그립 너비로 바를 잡고 양팔을 편 상태에서, 상체를 약 30도 정도 뒤로 젖히며 허리에 커브를 만들고 가슴을 내민다. 이것이 시작 자세다.", "어깨와 위팔을 아래로, 뒤로 당겨 바가 윗가슴에 닿을 때까지 상체를 끌어 올린다. 이 동작을 하는 동안 숨을 내쉰다. 팁: 완전히 수축된 지점에 도달하면 등 근육을 쥐어짜듯 수축시키는 데 집중한다. 상체는 공간을 이동하는 동안에도 고정된 상태를 유지하고 팔만 움직여야 한다. 아래팔은 바를 잡는 것 외에 다른 일을 하지 않는다.", "수축 자세에서 1초간 유지한 뒤, 숨을 들이마시며 팔이 완전히 펴지고 광배근이 완전히 늘어날 때까지 상체를 천천히 시작 자세로 내린다.", "정해진 반복 횟수만큼 이 동작을 반복한다."], en: ["Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.", "As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.", "Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.", "After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.", "Repeat this motion for the prescribed amount of repetitions."] },
  "친업": { s: "Chin-Up/0.jpg", e: "Chin-Up/1.jpg", k: ["손바닥이 몸통을 향하도록 어깨너비보다 좁은 그립으로 풀업 바를 잡는다.", "선택한 그립 너비로 바를 잡고 양팔을 앞으로 뻗은 상태에서, 허리에 아치를 만들고 가슴을 내밀며 몸통을 최대한 곧게 편다. 이것이 시작 자세다. 팁: 몸통을 최대한 곧게 유지하면 등 개입을 최소화하면서 이두근 자극을 극대화할 수 있다.", "숨을 내쉬면서 머리가 풀업 바 높이에 오도록 몸통을 끌어올린다. 이두근을 사용해 동작을 수행하는 데 집중한다. 팔꿈치는 몸에 가깝게 유지한다. 팁: 상체는 공간을 이동하는 동안 고정된 상태를 유지하고 오직 팔만 움직여야 한다. 전완은 바를 잡는 것 외에 다른 일을 해서는 안 된다.", "수축된 자세에서 1초간 이두근을 짜준 뒤, 팔이 완전히 펴질 때까지 몸통을 천천히 시작 자세로 내린다. 이 구간에서는 숨을 들이쉰다.", "권장 반복 횟수만큼 이 동작을 반복한다."], en: ["Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.", "As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.", "As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.", "After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.", "Repeat this motion for the prescribed amount of repetitions."] },
  "머신 로우": { s: "Leverage_Iso_Row/0.jpg", e: "Leverage_Iso_Row/1.jpg", k: ["핀에 적절한 중량을 걸고 핸들이 가슴 높이에 오도록 시트 높이를 조절한다. 뉴트럴 또는 오버핸드(엎어 쥐기) 그립으로 핸들을 잡는다. 이것이 시작 자세다.", "팔꿈치를 굽히면서 견갑골을 모아 핸들을 몸통 쪽으로 당긴다.", "동작의 끝에서 잠시 멈춘 뒤, 핸들을 천천히 시작 자세로 되돌린다. 여러 번 반복할 때는 근육에 긴장을 유지하기 위해 중량을 완전히 멈춤 지점까지 되돌리지 않는다."], en: ["Load an appropriate weight onto the pins and adjust the seat height so that the handles are at chest level. Grasp the handles with either a neutral or pronated grip. This will be your starting position.", "Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.", "Pause at the bottom of the motion, and then slowly return the handles to the starting position. For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked."] },
  "하이퍼익스텐션": { s: "Hyperextensions_Back_Extensions/0.jpg", e: "Hyperextensions_Back_Extensions/1.jpg", k: ["하이퍼익스텐션 벤치에 엎드려 발목을 발판 아래에 단단히 고정한다.", "가능하다면 상단 패드를 조절해 허벅지 윗부분이 넓은 패드에 평평하게 놓이도록 하고, 허리를 자유롭게 굽힐 수 있는 공간을 확보한다.", "몸을 곧게 편 상태에서 양팔을 가슴 앞에서 교차하거나(추천) 머리 뒤로 둔다. 이것이 시작 자세다. 팁: 교차한 팔 아래에 원판을 들면 추가 저항을 줄 수 있다.", "등을 편평하게 유지하면서 허리를 천천히 가능한 만큼 앞으로 굽힌다. 이 동작을 하는 동안 숨을 들이쉰다. 햄스트링이 시원하게 늘어나는 느낌이 들고 등을 둥글게 말지 않고는 더 내려갈 수 없을 때까지 계속 앞으로 굽힌다. 팁: 이 운동을 할 때 절대 등을 둥글게 말지 않는다. 사람마다 가동 범위가 다를 수 있는데, 핵심은 등을 말지 않는 선에서 몸이 허락하는 만큼만 내려가는 것이다.", "숨을 들이쉬면서 몸통을 천천히 시작 자세로 다시 들어올린다. 팁: 일직선을 넘어 등을 과도하게 아치로 젖히려는 유혹을 피한다. 또한 부상을 막기 위해 어느 순간에도 몸통을 반동으로 휘두르지 않는다.", "권장 반복 횟수만큼 반복한다."], en: ["Lie face down on a hyperextension bench, tucking your ankles securely under the footpads.", "Adjust the upper pad if possible so your upper thighs lie flat across the wide pad, leaving enough room for you to bend at the waist without any restriction.", "With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.", "Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you feel a nice stretch on the hamstrings and you can no longer keep going without a rounding of the back. Tip: Never round the back as you perform this exercise. Also, some people can go farther than others. The key thing is that you go as far as your body allows you to without rounding the back.", "Slowly raise your torso back to the initial position as you inhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.", "Repeat for the recommended amount of repetitions."] },
  "굿모닝": { s: "Good_Morning/0.jpg", e: "Good_Morning/1.jpg", k: ["바를 어깨 높이의 랙에 걸어 시작한다. 파워 스쿼트를 하듯 바를 어깨 위가 아니라 어깨 뒤쪽에 얹는다. 등을 단단히 조이고 견갑골을 모으며 무릎을 살짝 굽힌다. 랙에서 한 걸음 물러선다.", "엉덩이를 뒤로 빼면서 굽혀 상체가 바닥과 거의 평행이 될 때까지 숙인다. 등은 아치를 유지하고 경추(목뼈)는 올바른 정렬을 유지한다.", "둔근과 햄스트링을 사용해 엉덩이를 펴며 동작을 반대로 되돌린다. 시작 자세로 돌아올 때까지 계속한다."], en: ["Begin with a bar on a rack at shoulder height. Rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Step back from the rack.", "Begin by bending at the hips, moving them back as you bend over to near parallel. Keep your back arched and your cervical spine in proper alignment.", "Reverse the motion by extending through the hips with your glutes and hamstrings. Continue until you have returned to the starting position."] },
  "오버헤드 프레스": { s: "Barbell_Shoulder_Press/0.jpg", e: "Barbell_Shoulder_Press/1.jpg", k: ["스쿼트 랙 안의 등받이가 있는 벤치에 앉는다. 바벨을 머리 바로 위 높이에 위치시킨다. 오버핸드 그립(손바닥이 앞을 향하게)으로 바벨을 잡는다.", "올바른 그립 너비로 바벨을 들어올린 뒤, 팔을 완전히 펴 바를 머리 위로 들어올린다. 어깨 높이쯤, 머리보다 약간 앞에서 잡는다. 이것이 시작 자세다.", "숨을 들이쉬면서 바를 어깨까지 천천히 내린다.", "숨을 내쉬면서 바를 다시 시작 자세로 들어올린다.", "권장 반복 횟수만큼 반복한다."], en: ["Sit on a bench with back support in a squat rack. Position a barbell at a height that is just above your head. Grab the barbell with a pronated grip (palms facing forward).", "Once you pick up the barbell with the correct grip width, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.", "Lower the bar down to the shoulders slowly as you inhale.", "Lift the bar back up to the starting position as you exhale.", "Repeat for the recommended amount of repetitions."] },
  "밀리터리 프레스": { s: "Standing_Military_Press/0.jpg", e: "Standing_Military_Press/1.jpg", k: ["가슴 높이쯤의 바벨을 스쿼트 랙에 걸어 시작한다. 중량을 선택한 뒤 오버핸드(손바닥이 앞을 향하게) 그립으로 바벨을 잡는다. 양손 간격은 어깨너비보다 넓게 잡는다.", "무릎을 살짝 굽히고 바벨을 쇄골 위에 올린다. 가슴에 얹은 채로 바벨을 들어올린다. 한 걸음 물러서서 발을 어깨너비로 벌린다.", "올바른 그립 너비로 바벨을 든 뒤, 팔을 완전히 펴 바를 머리 위로 들어올린다. 어깨 높이쯤, 머리보다 약간 앞에서 잡는다. 이것이 시작 자세다.", "숨을 들이쉬면서 바를 쇄골까지 천천히 내린다.", "숨을 내쉬면서 바를 다시 시작 자세로 들어올린다.", "권장 반복 횟수만큼 반복한다."], en: ["Start by placing a barbell that is about chest high on a squat rack. Once you have selected the weights, grab the barbell using a pronated (palms facing forward) grip. Make sure to grip the bar wider than shoulder width apart from each other.", "Slightly bend the knees and place the barbell on your collar bone. Lift the barbell up keeping it lying on your chest. Take a step back and position your feet shoulder width apart from each other.", "Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.", "Lower the bar down to the collarbone slowly as you inhale.", "Lift the bar back up to the starting position as you exhale.", "Repeat for the recommended amount of repetitions."] },
  "덤벨 숄더 프레스": { s: "Dumbbell_Shoulder_Press/0.jpg", e: "Dumbbell_Shoulder_Press/1.jpg", k: ["양손에 덤벨을 든 채 등받이가 있는 밀리터리 프레스 벤치나 일반 벤치에 앉는다. 덤벨을 허벅지 위에 세워 올린다.", "이제 허벅지의 반동을 이용해 덤벨을 한쪽씩 어깨 높이까지 들어올린다.", "손바닥이 앞을 향하도록 손목을 돌린다. 이것이 시작 자세다.", "숨을 내쉬면서 덤벨이 맨 위에서 서로 닿을 때까지 위로 밀어올린다.", "맨 위 수축 자세에서 잠깐 멈춘 뒤, 숨을 들이쉬면서 천천히 중량을 시작 자세로 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["While holding a dumbbell in each hand, sit on a military press bench or utility bench that has back support. Place the dumbbells upright on top of your thighs.", "Now raise the dumbbells to shoulder height one at a time using your thighs to help propel them up into position.", "Make sure to rotate your wrists so that the palms of your hands are facing forward. This is your starting position.", "Now, exhale and push the dumbbells upward until they touch at the top.", "Then, after a brief pause at the top contracted position, slowly lower the weights back down to the starting position while inhaling.", "Repeat for the recommended amount of repetitions."] },
  "아놀드 프레스": { s: "Arnold_Dumbbell_Press/0.jpg", e: "Arnold_Dumbbell_Press/1.jpg", k: ["등받이가 있는 벤치에 앉아 손바닥이 몸을 향하고 팔꿈치를 굽힌 채로 덤벨 두 개를 가슴 위쪽 높이에서 몸 앞에 든다. 팁: 팔은 몸통 옆에 붙어 있어야 한다. 시작 자세는 덤벨 컬의 수축된 부분과 비슷해 보여야 한다.", "동작을 수행하려면, 손바닥이 앞을 향할 때까지 회전시키면서 덤벨을 들어올린다.", "팔이 머리 위로 곧게 펴질 때까지 계속 덤벨을 들어올린다. 이 구간에서는 숨을 내쉰다.", "맨 위에서 1초간 멈춘 뒤, 손바닥을 다시 몸 쪽으로 회전시키면서 덤벨을 원래 자세로 내리기 시작한다. 팁: 왼팔은 시계 반대 방향으로, 오른팔은 시계 방향으로 회전한다. 이 구간에서는 숨을 들이쉰다.", "권장 반복 횟수만큼 반복한다."], en: ["Sit on an exercise bench with back support and hold two dumbbells in front of you at about upper chest level with your palms facing your body and your elbows bent. Tip: Your arms should be next to your torso. The starting position should look like the contracted portion of a dumbbell curl.", "Now to perform the movement, raise the dumbbells as you rotate the palms of your hands until they are facing forward.", "Continue lifting the dumbbells until your arms are extended above you in straight arm position. Breathe out as you perform this portion of the movement.", "After a second pause at the top, begin to lower the dumbbells to the original position by rotating the palms of your hands towards you. Tip: The left arm will be rotated in a counter clockwise manner while the right one will be rotated clockwise. Breathe in as you perform this portion of the movement.", "Repeat for the recommended amount of repetitions."] },
  "숄더 프레스 머신": { s: "Leverage_Shoulder_Press/0.jpg", e: "Leverage_Shoulder_Press/1.jpg", k: ["핀에 적절한 중량을 걸고 키에 맞게 시트를 조절한다. 동작 시작 시 핸들이 어깨 위쪽 근처에 와야 한다. 가슴과 머리를 세우고 오버핸드 그립으로 핸들을 잡는다. 이것이 시작 자세다.", "팔꿈치를 펴며 핸들을 위로 밀어올린다.", "맨 위에서 잠깐 멈춘 뒤, 중량을 시작 자세 바로 위까지 되돌린다. 세트가 끝날 때까지 중량을 멈춤 지점까지 내리지 않아 근육의 긴장을 유지한다."], en: ["Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the shoulders at the beginning of the motion. Your chest and head should be up and handles held with a pronated grip. This will be your starting position.", "Press the handles upward by extending through the elbow.", "After a brief pause at the top, return the weight to just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete."] },
  "사이드 레터럴 레이즈": { s: "Side_Lateral_Raise/0.jpg", e: "Side_Lateral_Raise/1.jpg", k: ["덤벨 두 개를 들고 몸통을 곧게 편 채 서서, 손바닥이 몸을 향하도록 덤벨을 팔을 편 상태로 몸 옆에 둔다. 이것이 시작 자세다.", "몸통을 고정한 채(반동 금지) 팔꿈치를 살짝 굽히고 물을 잔에 따르듯 손을 약간 앞으로 기울여 덤벨을 옆으로 들어올린다. 팔이 바닥과 평행해질 때까지 계속 올린다. 이 동작을 하는 동안 숨을 내쉬고 맨 위에서 1초간 멈춘다.", "숨을 들이쉬면서 덤벨을 천천히 시작 자세로 다시 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.", "While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.", "Lower the dumbbells back down slowly to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."] },
  "케이블 레터럴 레이즈": { s: "Cable_Seated_Lateral_Raise/0.jpg", e: "Cable_Seated_Lateral_Raise/1.jpg", k: ["서로 마주 보는 두 개의 로우 풀리 중앙에 서서 바로 뒤에 플랫 벤치를 놓는다(몸과 수직 방향으로, 벤치의 좁은 끝이 뒤쪽에 오도록). 각 풀리에 사용할 중량을 선택한다.", "이제 뒤의 플랫 벤치 끝에 앉아 발을 무릎보다 앞에 둔다.", "등을 편평하게 유지하면서 앞으로 굽혀 몸통을 허벅지에 기댄다.", "누군가에게 풀리에 연결된 단일 핸들을 건네받는다. 중량을 선택한 뒤 오른손으로 왼쪽 풀리를, 왼손으로 오른쪽 풀리를 잡는다. 케이블은 무릎 아래로 지나가고 팔은 손바닥이 서로 마주 본 채 팔꿈치를 살짝 굽혀 뻗은 상태다. 이것이 시작 자세다.", "팔을 고정한 채 위팔을 옆으로 들어올려 바닥과 평행하고 어깨 높이가 될 때까지 올린다. 이 동작 중에 숨을 내쉬고 수축을 1초간 유지한다.", "숨을 들이쉬면서 팔을 천천히 시작 자세로 내린다.", "권장 반복 횟수만큼 반복한다. 팁: 운동 내내 위팔을 몸통과 수직으로, 팔꿈치를 고정된 각도(10~30도)로 유지한다."], en: ["Stand in the middle of two low pulleys that are opposite to each other and place a flat bench right behind you (in perpendicular fashion to you; the narrow edge of the bench should be the one behind you). Select the weight to be used on each pulley.", "Now sit at the edge of the flat bench behind you with your feet placed in front of your knees.", "Bend forward while keeping your back flat and rest your torso on the thighs.", "Have someone give you the single handles attached to the pulleys. Grasp the left pulley with the right hand and the right pulley with the left after you select your weight. The pulleys should run under your knees and your arms will be extended with palms facing each other and a slight bend at the elbows. This will be the starting position.", "While keeping the arms stationary, raise the upper arms to the sides until they are parallel to the floor and at shoulder height. Exhale during the execution of this movement and hold the contraction for a second.", "Slowly lower your arms to the starting position as you inhale.", "Repeat for the recommended amount of repetitions. Tip: Maintain upper arms perpendicular to torso and a fixed elbow position (10 degree to 30 degree angle) throughout exercise."] },
  "프론트 레이즈": { s: "Front_Dumbbell_Raise/0.jpg", e: "Front_Dumbbell_Raise/1.jpg", k: ["덤벨 두 개를 들고 몸통을 곧게 편 채 서서, 손바닥이 허벅지를 향하도록 덤벨을 팔을 편 상태로 허벅지 앞에 둔다. 이것이 시작 자세다.", "몸통을 고정한 채(반동 금지) 팔꿈치를 살짝 굽히고 손바닥이 항상 아래를 향하도록 하여 왼쪽 덤벨을 앞으로 들어올린다. 팔이 바닥과 평행선보다 약간 위에 올 때까지 계속 올린다. 이 구간에서 숨을 내쉬고 맨 위에서 1초간 멈춘다. 1초 멈춤 후 숨을 들이쉰다.", "이제 오른쪽 덤벨을 동시에 들어올리면서 왼쪽 덤벨을 천천히 시작 자세로 내린다.", "양팔 모두 권장 반복 횟수를 채울 때까지 이런 식으로 번갈아 계속한다."], en: ["Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.", "While maintaining the torso stationary (no swinging), lift the left dumbbell to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top. Inhale after the second pause.", "Now lower the dumbbell back down slowly to the starting position as you simultaneously lift the right dumbbell.", "Continue alternating in this fashion until all of the recommended amount of repetitions have been performed for each arm."] },
  "리어 델트 플라이": { s: "Reverse_Flyes/0.jpg", e: "Reverse_Flyes/1.jpg", k: ["시작하려면 가슴과 배가 인클라인 면에 눌리도록 인클라인 벤치에 엎드린다. 양손에 손바닥이 서로 마주 보도록(뉴트럴 그립) 덤벨을 든다.", "팔을 앞으로 뻗어 벤치의 각도와 수직이 되게 한다. 발끝으로 바닥을 누르며 다리는 고정한다. 이것이 시작 자세다.", "팔꿈치를 살짝 굽힌 상태를 유지하며 숨을 내쉬면서 덤벨을 호를 그리듯 바깥쪽 옆으로 벌려 올린다. 팁: 견갑골을 모아주면 이 운동의 효과를 가장 잘 얻을 수 있다.", "팔은 바닥과 평행해질 때까지 들어올린다.", "수축을 느끼며 숨을 들이쉬면서 천천히 덤벨을 시작 자세로 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).", "Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.", "Maintaining the slight bend of the elbows, move the weights out and away from each other (to the side) in an arc motion while exhaling. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.", "The arms should be elevated until they are parallel to the floor.", "Feel the contraction and slowly lower the weights back down to the starting position while inhaling.", "Repeat for the recommended amount of repetitions."] },
  "리버스 펙 덱": { s: "Reverse_Machine_Flyes/0.jpg", e: "Reverse_Machine_Flyes/1.jpg", k: ["핸들이 완전히 뒤쪽으로 오도록 조절한다. 적절한 중량을 선택하고 핸들이 어깨 높이에 오도록 시트 높이를 조절한다. 손바닥이 안쪽을 향하도록 핸들을 잡는다. 이것이 시작 자세다.", "반원을 그리는 동작으로 후면 삼각근을 수축시키며 손을 옆으로 그리고 뒤로 당긴다.", "동작 내내 팔을 살짝 굽힌 상태를 유지하고, 모든 움직임이 어깨 관절에서 일어나도록 한다.", "동작의 끝에서 잠시 멈춘 뒤, 천천히 중량을 시작 자세로 되돌린다."], en: ["Adjust the handles so that they are fully to the rear. Make an appropriate weight selection and adjust the seat height so the handles are at shoulder level. Grasp the handles with your hands facing inwards. This will be your starting position.", "In a semicircular motion, pull your hands out to your side and back, contracting your rear delts.", "Keep your arms slightly bent throughout the movement, with all of the motion occurring at the shoulder joint.", "Pause at the rear of the movement, and slowly return the weight to the starting position."] },
  "페이스 풀": { s: "Face_Pull/0.jpg", e: "Face_Pull/1.jpg", k: ["로프나 듀얼 핸들이 달린 하이 풀리를 마주 보고 서서, 당기면서 양손을 벌리며 중량을 얼굴 쪽으로 곧장 당긴다. 위팔은 바닥과 평행하게 유지한다."], en: ["Facing a high pulley with a rope or dual handles attached, pull the weight directly towards your face, separating your hands as you do so. Keep your upper arms parallel to the ground."] },
  "업라이트 로우": { s: "Upright_Barbell_Row/0.jpg", e: "Upright_Barbell_Row/1.jpg", k: ["어깨너비보다 약간 좁은 오버핸드 그립으로 바벨을 잡는다. 바는 팔을 편 채 팔꿈치를 살짝 굽혀 허벅지 위쪽에 놓여 있어야 한다. 등도 곧게 편다. 이것이 시작 자세다.", "이제 숨을 내쉬면서 어깨 측면을 사용해 바를 들어올리며 팔꿈치를 위로 옆으로 올린다. 바를 몸에 가깝게 유지하며 들어올린다. 바가 턱에 거의 닿을 때까지 계속 올린다. 팁: 팔꿈치가 동작을 주도해야 하며 항상 전완보다 높아야 한다. 몸통은 고정하고 동작의 맨 위에서 1초간 멈춘다.", "바를 천천히 시작 자세로 다시 내린다. 이 구간에서는 숨을 들이쉰다.", "권장 반복 횟수만큼 반복한다."], en: ["Grasp a barbell with an overhand grip that is slightly less than shoulder width. The bar should be resting on the top of your thighs with your arms extended and a slight bend in your elbows. Your back should also be straight. This will be your starting position.", "Now exhale and use the sides of your shoulders to lift the bar, raising your elbows up and to the side. Keep the bar close to your body as you raise it. Continue to lift the bar until it nearly touches your chin. Tip: Your elbows should drive the motion, and should always be higher than your forearms. Remember to keep your torso stationary and pause for a second at the top of the movement.", "Lower the bar back down slowly to the starting position. Inhale as you perform this portion of the movement.", "Repeat for the recommended amount of repetitions."] },
  "바벨 컬": { s: "Barbell_Curl/0.jpg", e: "Barbell_Curl/1.jpg", k: ["몸통을 곧게 세우고 서서 어깨너비 그립으로 바벨을 든다. 손바닥은 앞을 향하고 팔꿈치는 몸통에 가깝게 둔다. 이것이 시작 자세다.", "위팔을 고정한 채, 숨을 내쉬면서 이두근을 수축시켜 중량을 앞으로 컬한다. 팁: 오직 전완만 움직여야 한다.", "이두근이 완전히 수축되고 바가 어깨 높이에 올 때까지 동작을 계속한다. 수축 자세를 1초간 유지하며 이두근을 강하게 짜준다.", "숨을 들이쉬면서 천천히 바를 시작 자세로 되돌리기 시작한다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand up with your torso upright while holding a barbell at a shoulder-width grip. The palm of your hands should be facing forward and the elbows should be close to the torso. This will be your starting position.", "While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.", "Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.", "Slowly begin to bring the bar back to starting position as your breathe in.", "Repeat for the recommended amount of repetitions."] },
  "이지바 컬": { s: "EZ-Bar_Curl/0.jpg", e: "EZ-Bar_Curl/1.jpg", k: ["EZ 컬 바의 넓은 바깥쪽 손잡이를 잡고 곧게 선다. 손바닥은 앞을 향하되 바의 모양 때문에 약간 안쪽으로 기울어진다. 팔꿈치는 몸통에 가깝게 둔다. 이것이 시작 자세다.", "이제 위팔을 고정한 채 숨을 내쉬면서 이두근을 수축시켜 중량을 앞으로 컬한다. 오직 전완만 움직이는 데 집중한다.", "이두근이 완전히 수축되고 바가 어깨 높이에 올 때까지 계속 들어올린다. 맨 위 수축 자세를 잠시 유지하며 이두근을 짜준다.", "그다음 숨을 들이쉬면서 천천히 바를 시작 자세로 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand up straight while holding an EZ curl bar at the wide outer handle. The palms of your hands should be facing forward and slightly tilted inward due to the shape of the bar. Keep your elbows close to your torso. This will be your starting position.", "Now, while keeping your upper arms stationary, exhale and curl the weights forward while contracting the biceps. Focus on only moving your forearms.", "Continue to raise the weight until your biceps are fully contracted and the bar is at shoulder level. Hold the top contracted position for a moment and squeeze the biceps.", "Then inhale and slowly lower the bar back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "덤벨 컬": { s: "Dumbbell_Bicep_Curl/0.jpg", e: "Dumbbell_Bicep_Curl/1.jpg", k: ["양손에 덤벨을 든 채 팔을 펴고 곧게 선다. 팔꿈치를 몸통에 가깝게 두고 손바닥이 앞을 향할 때까지 돌린다. 이것이 시작 자세다.", "이제 위팔을 고정한 채 숨을 내쉬면서 이두근을 수축시켜 중량을 컬한다. 이두근이 완전히 수축되고 덤벨이 어깨 높이에 올 때까지 계속 들어올린다. 이두근을 짜주며 수축 자세를 잠시 유지한다.", "그다음 숨을 들이쉬면서 천천히 덤벨을 시작 자세로 내리기 시작한다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand up straight with a dumbbell in each hand at arm's length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.", "Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.", "Then, inhale and slowly begin to lower the dumbbells back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "해머 컬": { s: "Hammer_Curls/0.jpg", e: "Hammer_Curls/1.jpg", k: ["몸통을 곧게 세우고 서서 양손에 덤벨을 팔을 편 상태로 든다. 팔꿈치는 몸통에 가깝게 둔다.", "손바닥은 몸통을 향해야 한다. 이것이 시작 자세다.", "이제 위팔을 고정한 채 숨을 내쉬면서 이두근을 수축시켜 중량을 앞으로 컬한다. 이두근이 완전히 수축되고 덤벨이 어깨 높이에 올 때까지 계속 들어올린다. 이두근을 짜주며 수축 자세를 잠시 유지한다. 팁: 팔꿈치를 고정하고 오직 전완만 움직이는 데 집중한다.", "잠시 멈춘 뒤, 숨을 들이쉬면서 천천히 덤벨을 시작 자세로 내리기 시작한다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.", "The palms of the hands should be facing your torso. This will be your starting position.", "Now, while holding your upper arm stationary, exhale and curl the weight forward while contracting the biceps. Continue to raise the weight until the biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief moment as you squeeze the biceps. Tip: Focus on keeping the elbow stationary and only moving your forearm.", "After the brief pause, inhale and slowly begin the lower the dumbbells back down to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "인클라인 덤벨 컬": { s: "Incline_Dumbbell_Curl/0.jpg", e: "Incline_Dumbbell_Curl/1.jpg", k: ["양손에 덤벨을 팔을 편 상태로 들고 인클라인 벤치에 기대어 앉는다. 팔꿈치를 몸통에 가깝게 두고 손바닥이 앞을 향할 때까지 돌린다. 이것이 시작 자세다.", "위팔을 고정한 채 숨을 내쉬면서 이두근을 수축시켜 중량을 앞으로 컬한다. 오직 전완만 움직여야 한다. 이두근이 완전히 수축되고 덤벨이 어깨 높이에 올 때까지 동작을 계속한다. 수축 자세를 1초간 유지한다.", "숨을 들이쉬면서 천천히 덤벨을 시작 자세로 되돌리기 시작한다.", "권장 반복 횟수만큼 반복한다."], en: ["Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.", "While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.", "Slowly begin to bring the dumbbells back to starting position as your breathe in.", "Repeat for the recommended amount of repetitions."] },
  "프리처 컬": { s: "Preacher_Curl/0.jpg", e: "Preacher_Curl/1.jpg", k: ["이 동작을 하려면 프리처 벤치와 EZ 바가 필요하다. EZ 컬 바의 가까운 안쪽 손잡이를 잡는다(누군가 바를 건네주는 것이 가장 좋고, 아니면 대부분의 프리처 벤치에 있는 앞쪽 거치대에서 바를 잡는다). 손바닥은 앞을 향하되 바의 모양 때문에 약간 안쪽으로 기울어진다.", "위팔을 프리처 벤치 패드에 대고 가슴을 붙인 채, EZ 컬 바를 팔을 편 상태로 어깨 높이에 든다. 이것이 시작 자세다.", "숨을 들이쉬면서 위팔이 펴지고 이두근이 완전히 늘어날 때까지 천천히 바를 내린다.", "숨을 내쉬면서 이두근을 사용해 이두근이 완전히 수축되고 바가 어깨 높이에 올 때까지 중량을 컬한다. 이두근을 강하게 짜주며 이 자세를 1초간 유지한다.", "권장 반복 횟수만큼 반복한다."], en: ["To perform this movement you will need a preacher bench and an E-Z bar. Grab the E-Z curl bar at the close inner handle (either have someone hand you the bar which is preferable or grab the bar from the front bar rest provided by most preacher benches). The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar.", "With the upper arms positioned against the preacher bench pad and the chest against it, hold the E-Z Curl Bar at shoulder length. This will be your starting position.", "As you breathe in, slowly lower the bar until your upper arm is extended and the biceps is fully stretched.", "As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the bar is at shoulder height. Squeeze the biceps hard and hold this position for a second.", "Repeat for the recommended amount of repetitions."] },
  "컨센트레이션 컬": { s: "Concentration_Curls/0.jpg", e: "Concentration_Curls/1.jpg", k: ["플랫 벤치에 앉아 다리 사이 앞에 덤벨 하나를 둔다. 다리는 벌리고 무릎을 굽혀 발을 바닥에 붙인다.", "오른팔로 덤벨을 집어 든다. 오른쪽 위팔 뒤쪽을 오른쪽 허벅지 안쪽 위에 댄다. 손바닥이 허벅지에서 멀어져 앞을 향할 때까지 돌린다. 팁: 팔은 펴져 있고 덤벨은 바닥 위에 떠 있어야 한다. 이것이 시작 자세다.", "위팔을 고정한 채 숨을 내쉬면서 이두근을 수축시켜 중량을 앞으로 컬한다. 오직 전완만 움직여야 한다. 이두근이 완전히 수축되고 덤벨이 어깨 높이에 올 때까지 동작을 계속한다. 팁: 동작의 맨 위에서 새끼손가락이 엄지보다 높게 오도록 한다. 이렇게 하면 확실한 수축이 보장된다. 이두근을 짜주며 수축 자세를 1초간 유지한다.", "숨을 들이쉬면서 천천히 덤벨을 시작 자세로 되돌리기 시작한다. 주의: 어느 순간에도 반동 동작을 피한다.", "권장 반복 횟수만큼 반복한다. 그다음 왼팔로 동작을 반복한다."], en: ["Sit down on a flat bench with one dumbbell in front of you between your legs. Your legs should be spread with your knees bent and feet on the floor.", "Use your right arm to pick the dumbbell up. Place the back of your right upper arm on the top of your inner right thigh. Rotate the palm of your hand until it is facing forward away from your thigh. Tip: Your arm should be extended and the dumbbell should be above the floor. This will be your starting position.", "While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: At the top of the movement make sure that the little finger of your arm is higher than your thumb. This guarantees a good contraction. Hold the contracted position for a second as you squeeze the biceps.", "Slowly begin to bring the dumbbells back to starting position as your breathe in. Caution: Avoid swinging motions at any time.", "Repeat for the recommended amount of repetitions. Then repeat the movement with the left arm."] },
  "케이블 컬": { s: "Standing_Biceps_Cable_Curl/0.jpg", e: "Standing_Biceps_Cable_Curl/1.jpg", k: ["로우 풀리에 연결된 케이블 컬 바를 든 채 몸통을 곧게 세우고 선다. 어깨너비로 케이블 바를 잡고 팔꿈치를 몸통에 가깝게 둔다. 손바닥은 위를 향해야 한다(언더핸드 그립). 이것이 시작 자세다.", "위팔을 고정한 채 숨을 내쉬면서 이두근을 수축시켜 중량을 컬한다. 오직 전완만 움직여야 한다. 이두근이 완전히 수축되고 바가 어깨 높이에 올 때까지 동작을 계속한다. 근육을 짜주며 수축 자세를 1초간 유지한다.", "숨을 들이쉬면서 천천히 컬 바를 시작 자세로 되돌리기 시작한다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand up with your torso upright while holding a cable curl bar that is attached to a low pulley. Grab the cable bar at shoulder width and keep the elbows close to the torso. The palm of your hands should be facing up (supinated grip). This will be your starting position.", "While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.", "Slowly begin to bring the curl bar back to starting position as your breathe in.", "Repeat for the recommended amount of repetitions."] },
  "스파이더 컬": { s: "Spider_Curl/0.jpg", e: "Spider_Curl/1.jpg", k: ["평소 앉는 프리처 벤치 부분에 바를 올려놓고 시작한다. 바벨이 균형을 잃고 떨어지지 않도록 제대로 정렬한다.", "프리처 벤치의 앞쪽(보통 팔을 얹는 부분)으로 이동해, 몸통과 배가 프리처 벤치 앞면에 눌리도록 45도 경사로 엎드린다.", "발(특히 발끝)이 바닥에 잘 고정되도록 하고, 위팔을 프리처 벤치 안쪽 패드 위에 올린다.", "팔을 사용해 언더핸드 그립(손바닥이 위를 향하게)으로 어깨너비 정도 또는 그보다 약간 좁게 바벨을 잡는다.", "숨을 내쉬면서 천천히 바벨을 위로 들어올리기 시작한다. 이두근을 짜주며 수축 자세를 1초간 유지한다.", "숨을 들이쉬면서 천천히 바벨을 시작 자세로 되돌리기 시작한다.", "권장 반복 횟수만큼 반복한다."], en: ["Start out by setting the bar on the part of the preacher bench that you would normally sit on. Make sure to align the barbell properly so that it is balanced and will not fall off.", "Move to the front side of the preacher bench (the part where the arms usually lay) and position yourself to lay at a 45 degree slant with your torso and stomach pressed against the front side of the preacher bench.", "Make sure that your feet (especially the toes) are well positioned on the floor and place your upper arms on top of the pad located on the inside part of the preacher bench.", "Use your arms to grab the barbell with a supinated grip (palms facing up) at about shoulder width apart or slightly closer from each other.", "Slowly begin to lift the barbell upwards and exhale. Hold the contracted position for a second as you squeeze the biceps.", "Slowly begin to bring the barbell back to the starting position as your breathe in. .", "Repeat for the recommended amount of repetitions."] },
  "머신 컬": { s: "Machine_Bicep_Curl/0.jpg", e: "Machine_Bicep_Curl/1.jpg", k: ["시트를 적절한 높이로 조절하고 중량을 선택한다. 위팔을 패드에 대고 핸들을 잡는다. 이것이 시작 자세다.", "팔꿈치를 굽혀 전완을 위팔 쪽으로 당기며 동작을 수행한다.", "동작의 맨 위에서 잠시 멈춘 뒤, 천천히 중량을 시작 자세로 되돌린다.", "세트가 끝날 때까지 중량을 멈춤 지점까지 완전히 되돌리지 않아 근육의 긴장을 유지한다."], en: ["Adjust the seat to the appropriate height and make your weight selection. Place your upper arms against the pads and grasp the handles. This will be your starting position.", "Perform the movement by flexing the elbow, pulling your lower arm towards your upper arm.", "Pause at the top of the movement, and then slowly return the weight to the starting position.", "Avoid returning the weight all the way to the stops until the set is complete to keep tension on the muscles being worked."] },
  "클로즈 그립 벤치프레스": { s: "Close-Grip_Barbell_Bench_Press/0.jpg", e: "Close-Grip_Barbell_Bench_Press/1.jpg", k: ["플랫 벤치에 등을 대고 눕습니다. 어깨너비 정도의 좁은 그립으로 바를 랙에서 들어 팔을 완전히 편 채 몸 위로 곧게 듭니다. 이 자세가 시작 자세입니다.", "숨을 들이마시며 바가 가슴 중앙에 닿을 때까지 천천히 내립니다. 팁: 일반 벤치프레스와 달리 삼두 개입을 극대화하기 위해 팔꿈치를 항상 몸통 가까이 붙이세요.", "1초 멈춘 뒤 숨을 내쉬며 삼두 힘으로 바를 밀어 시작 자세로 되돌립니다. 수축 지점에서 팔을 완전히 펴 1초간 버틴 뒤 다시 천천히 내립니다. 팁: 내리는 동작은 올리는 동작보다 최소 두 배 느리게 하세요.", "정해진 반복 횟수만큼 동작을 반복합니다.", "끝나면 바를 랙에 다시 걸어둡니다."], en: ["Lie back on a flat bench. Using a close grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.", "As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that - as opposed to a regular bench press - you keep the elbows close to the torso at all times in order to maximize triceps involvement.", "After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.", "Repeat the movement for the prescribed amount of repetitions.", "When you are done, place the bar back in the rack."] },
  "트라이셉스 푸시다운": { s: "Triceps_Pushdown/0.jpg", e: "Triceps_Pushdown/1.jpg", k: ["하이 풀리에 스트레이트 바나 앵글 바를 걸고 어깨너비로 오버핸드 그립(손바닥이 아래를 향함)으로 잡습니다.", "상체를 곧게 세우고 아주 살짝 앞으로 기울인 채 서서, 위팔을 몸에 붙이고 바닥과 수직이 되게 합니다. 바를 잡은 팔뚝은 풀리를 향해 위쪽을 가리킵니다. 이 자세가 시작 자세입니다.", "삼두 힘으로 바를 허벅지 앞에 닿고 팔이 바닥과 수직으로 완전히 펴질 때까지 내립니다. 위팔은 항상 몸통 옆에 고정하고 팔뚝만 움직여야 합니다. 이 동작을 하며 숨을 내쉽니다.", "수축 지점에서 1초간 버틴 뒤 바를 천천히 시작 지점으로 올립니다. 이 동작을 하며 숨을 들이마십니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Attach a straight or angled bar to a high pulley and grab with an overhand grip (palms facing down) at shoulder width.", "Standing upright with the torso straight and a very small inclination forward, bring the upper arms close to your body and perpendicular to the floor. The forearms should be pointing up towards the pulley as they hold the bar. This is your starting position.", "Using the triceps, bring the bar down until it touches the front of your thighs and the arms are fully extended perpendicular to the floor. The upper arms should always remain stationary next to your torso and only the forearms should move. Exhale as you perform this movement.", "After a second hold at the contracted position, bring the bar slowly up to the starting point. Breathe in as you perform this step.", "Repeat for the recommended amount of repetitions."] },
  "로프 푸시다운": { s: "Triceps_Pushdown_-_Rope_Attachment/0.jpg", e: "Triceps_Pushdown_-_Rope_Attachment/1.jpg", k: ["하이 풀리에 로프를 걸고 뉴트럴 그립(손바닥이 서로 마주보게)으로 잡습니다.", "상체를 곧게 세우고 아주 살짝 앞으로 기울인 채 서서, 위팔을 몸에 붙이고 바닥과 수직이 되게 합니다. 로프를 손바닥이 마주보게 잡은 팔뚝은 풀리를 향해 위쪽을 가리킵니다. 이 자세가 시작 자세입니다.", "삼두 힘으로 로프를 내리면서 로프 양쪽 끝을 허벅지 옆으로 벌립니다. 동작이 끝나면 팔이 완전히 펴져 바닥과 수직이 됩니다. 위팔은 항상 몸통 옆에 고정하고 팔뚝만 움직여야 합니다. 이 동작을 하며 숨을 내쉽니다.", "수축 지점에서 1초간 버틴 뒤 로프를 천천히 시작 지점으로 올립니다. 이 동작을 하며 숨을 들이마십니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Attach a rope attachment to a high pulley and grab with a neutral grip (palms facing each other).", "Standing upright with the torso straight and a very small inclination forward, bring the upper arms close to your body and perpendicular to the floor. The forearms should be pointing up towards the pulley as they hold the rope with the palms facing each other. This is your starting position.", "Using the triceps, bring the rope down as you bring each side of the rope to the side of your thighs. At the end of the movement the arms are fully extended and perpendicular to the floor. The upper arms should always remain stationary next to your torso and only the forearms should move. Exhale as you perform this movement.", "After holding for a second, at the contracted position, bring the rope slowly up to the starting point. Breathe in as you perform this step.", "Repeat for the recommended amount of repetitions."] },
  "오버헤드 트라이셉스 익스텐션": { s: "Seated_Triceps_Press/0.jpg", e: "Seated_Triceps_Press/1.jpg", k: ["등받이가 있는 벤치에 앉아 덤벨 하나를 양손으로 잡고 팔을 편 채 머리 위로 듭니다. 팁: 무게가 무겁다면 다른 사람에게 건네받는 편이 좋습니다. 덤벨은 손바닥 위에 얹고 엄지로 감싸 쥐며, 손바닥은 안쪽을 향하게 합니다. 이 자세가 시작 자세입니다.", "위팔을 머리 가까이(팔꿈치를 안으로 모으고) 바닥과 수직으로 유지한 채, 팔뚝이 이두에 닿을 때까지 덤벨을 머리 뒤로 반원을 그리며 내립니다. 팁: 위팔은 고정하고 팔뚝만 움직여야 합니다. 이 동작을 하며 숨을 들이마십니다.", "삼두 힘으로 덤벨을 들어올려 시작 자세로 되돌립니다. 이 동작을 하며 숨을 내쉽니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm's length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position.", "Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.", "Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.", "Repeat for the recommended amount of repetitions."] },
  "케이블 오버헤드 익스텐션": { s: "Cable_Rope_Overhead_Triceps_Extension/0.jpg", e: "Cable_Rope_Overhead_Triceps_Extension/1.jpg", k: ["케이블 머신의 로우 풀리에 로프를 겁니다.", "로프를 양손으로 잡고 뉴트럴 그립(손바닥이 서로 마주보게)으로 손을 머리 바로 위로 뻗어 팔을 폅니다. 팔꿈치는 머리 가까이 모으고 팔은 바닥과 수직으로 하며 주먹은 천장을 향하게 합니다. 이 자세가 시작 자세입니다.", "위팔을 고정한 채 로프를 천천히 머리 뒤로 내립니다. 이 동작을 하며 숨을 들이마시고 삼두가 완전히 늘어난 지점에서 멈춥니다.", "숨을 내쉬며 삼두를 수축시켜 시작 자세로 되돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Attach a rope to the bottom pulley of the pulley machine.", "Grasping the rope with both hands, extend your arms with your hands directly above your head using a neutral grip (palms facing each other). Your elbows should be in close to your head and the arms should be perpendicular to the floor with the knuckles aimed at the ceiling. This will be your starting position.", "Slowly lower the rope behind your head as you hold the upper arms stationary. Inhale as you perform this movement and pause when your triceps are fully stretched.", "Return to the starting position by flexing your triceps as you breathe out.", "Repeat for the recommended amount of repetitions."] },
  "스컬 크러셔": { s: "EZ-Bar_Skullcrusher/0.jpg", e: "EZ-Bar_Skullcrusher/1.jpg", k: ["벤치에 누워 좁은 그립으로 이지바를 들고 팔꿈치를 안으로 모아 잡습니다. 팔은 바닥과 수직이 되게 합니다. 이 자세가 시작 자세입니다.", "위팔을 고정한 채 팔꿈치를 굽혀 바를 내립니다. 이 동작을 하며 숨을 들이마십니다. 바가 이마 바로 위에 오면 멈춥니다.", "숨을 내쉬며 팔꿈치를 펴 바를 시작 자세로 들어올립니다.", "반복합니다."], en: ["Using a close grip, lift the EZ bar and hold it with your elbows in as you lie on the bench. Your arms should be perpendicular to the floor. This will be your starting position.", "Keeping the upper arms stationary, lower the bar by allowing the elbows to flex. Inhale as you perform this portion of the movement. Pause once the bar is directly above the forehead.", "Lift the bar back to the starting position by extending the elbow and exhaling.", "Repeat."] },
  "트라이셉스 킥백": { s: "Tricep_Dumbbell_Kickback/0.jpg", e: "Tricep_Dumbbell_Kickback/1.jpg", k: ["양손에 덤벨을 들고 손바닥이 몸통을 향하게 합니다. 등을 곧게 펴고 무릎을 살짝 굽힌 채 허리를 앞으로 숙입니다. 상체는 바닥과 거의 평행이 되어야 합니다. 머리는 들고 있으세요. 위팔은 몸통에 붙이고 바닥과 평행하게 하며, 덤벨을 든 팔뚝은 바닥을 향하게 합니다. 팔뚝과 위팔은 90도 각도를 이뤄야 합니다. 이 자세가 시작 자세입니다.", "이제 위팔을 고정한 채 숨을 내쉬며 삼두 힘으로 팔이 완전히 펴질 때까지 덤벨을 들어올립니다. 팔뚝만 움직이는 데 집중하세요.", "정점의 수축 지점에서 잠시 멈춘 뒤 숨을 들이마시며 덤벨을 천천히 시작 자세로 내립니다.", "정해진 반복 횟수만큼 동작을 반복합니다."], en: ["Start with a dumbbell in each hand and your palms facing your torso. Keep your back straight with a slight bend in the knees and bend forward at the waist. Your torso should be almost parallel to the floor. Make sure to keep your head up. Your upper arms should be close to your torso and parallel to the floor. Your forearms should be pointed towards the floor as you hold the weights. There should be a 90-degree angle formed between your forearm and upper arm. This is your starting position.", "Now, while keeping your upper arms stationary, exhale and use your triceps to lift the weights until the arm is fully extended. Focus on moving the forearm.", "After a brief pause at the top contraction, inhale and slowly lower the dumbbells back down to the starting position.", "Repeat the movement for the prescribed amount of repetitions."] },
  "벤치 딥스": { s: "Bench_Dips/0.jpg", e: "Bench_Dips/1.jpg", k: ["이 운동을 하려면 등 뒤에 벤치를 놓아야 합니다. 벤치를 몸과 수직으로 두고 벤치를 등진 채, 팔을 완전히 펴 어깨너비로 벤치 모서리를 잡습니다. 다리는 앞으로 뻗어 골반에서 굽혀 상체와 수직이 되게 합니다. 이 자세가 시작 자세입니다.", "숨을 들이마시며 팔꿈치를 굽혀 위팔과 팔뚝 사이 각도가 90도보다 조금 작아질 때까지 몸을 천천히 내립니다. 팁: 동작 내내 팔꿈치를 최대한 붙이세요. 팔뚝은 항상 아래를 향해야 합니다.", "삼두 힘으로 상체를 다시 밀어올려 시작 자세로 되돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["For this exercise you will need to place a bench behind your back. With the bench perpendicular to your body, and while looking away from it, hold on to the bench on its edge with the hands fully extended, separated at shoulder width. The legs will be extended forward, bent at the waist and perpendicular to your torso. This will be your starting position.", "Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.", "Using your triceps to bring your torso up again, lift yourself back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "다이아몬드 푸시업": { s: "Push-Ups_-_Close_Triceps_Position/0.jpg", e: "Push-Ups_-_Close_Triceps_Position/1.jpg", k: ["바닥에 엎드려 손을 어깨너비보다 좁게 모아 짚습니다. 팔을 편 채 상체를 들어 지탱하세요.", "숨을 들이마시며 가슴이 바닥에 거의 닿을 때까지 몸을 내립니다.", "삼두와 가슴 근육의 일부를 사용해 상체를 시작 자세로 밀어올리며 가슴을 쥐어짭니다. 이 동작을 하며 숨을 내쉽니다.", "수축 지점에서 1초 멈춘 뒤 정해진 반복 횟수만큼 동작을 반복합니다."], en: ["Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms' length.", "Lower yourself until your chest almost touches the floor as you inhale.", "Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.", "After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."] },
  "리스트 컬": { s: "Seated_Palm-Up_Barbell_Wrist_Curl/0.jpg", e: "Seated_Palm-Up_Barbell_Wrist_Curl/1.jpg", k: ["손바닥이 위를 향하게 양손으로 바벨을 잡고, 손 간격은 어깨너비 정도로 벌립니다.", "발을 어깨너비보다 조금 넓게 벌려 바닥에 평평하게 딛습니다.", "앞으로 숙여 손바닥이 위를 향한 채 팔뚝을 허벅지 위에 올립니다. 팁: 손목 앞쪽이 무릎 위에 오도록 하세요. 이 자세가 시작 자세입니다.", "그립을 단단히 유지하며 숨을 들이마시고 바를 최대한 낮게 내립니다.", "이제 숨을 내쉬며 팔뚝을 수축시켜 바를 최대한 높이 말아 올립니다. 정점에서 1초간 수축을 유지하세요. 팁: 손목만 움직여야 합니다."], en: ["Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.", "Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.", "Lean forward and place your forearms on top of your upper thighs with your palms up. Tip: Make sure that the front of the wrists lay on top of your knees. This will be your starting position.", "Lower the bar as far as possible while inhaling and keeping a tight grip.", "Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move."] },
  "리버스 리스트 컬": { s: "Seated_Palms-Down_Barbell_Wrist_Curl/0.jpg", e: "Seated_Palms-Down_Barbell_Wrist_Curl/1.jpg", k: ["손바닥이 아래를 향하게 양손으로 바벨을 잡고, 손 간격은 어깨너비 정도로 벌립니다.", "발을 어깨너비보다 조금 넓게 벌려 바닥에 평평하게 딛습니다.", "앞으로 숙여 손바닥이 아래를 향한 채 팔뚝을 허벅지 위에 올립니다. 팁: 손목 뒤쪽이 무릎 위에 오도록 하세요. 이 자세가 시작 자세입니다.", "그립을 단단히 유지하며 숨을 들이마시고 바를 최대한 낮게 내립니다.", "이제 숨을 내쉬며 팔뚝을 수축시켜 바를 최대한 높이 말아 올립니다. 정점에서 1초간 수축을 유지하세요. 팁: 손목만 움직여야 합니다."], en: ["Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width.", "Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.", "Lean forward and place your forearms on top of your upper thighs with your palms down. Tip: Make sure that the back of the wrists lay on top of your knees. This will be your starting position.", "Lower the bar as far as possible while inhaling and keeping a tight grip.", "Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move."] },
  "리버스 바벨 컬": { s: "Reverse_Barbell_Curl/0.jpg", e: "Reverse_Barbell_Curl/1.jpg", k: ["상체를 곧게 세우고 서서 팔꿈치를 몸통에 붙인 채 어깨너비로 바벨을 잡습니다. 손바닥은 아래를 향하게 합니다(오버핸드 그립). 이 자세가 시작 자세입니다.", "위팔을 고정한 채 숨을 내쉬며 이두를 수축시켜 바를 말아 올립니다. 팔뚝만 움직여야 합니다. 이두가 완전히 수축되고 바가 어깨 높이에 올 때까지 동작을 이어갑니다. 수축 지점에서 근육을 쥐어짜며 1초간 버팁니다.", "숨을 들이마시며 바를 천천히 시작 자세로 되돌립니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Stand up with your torso upright while holding a barbell at shoulder width with the elbows close to the torso. The palm of your hands should be facing down (pronated grip). This will be your starting position.", "While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.", "Slowly begin to bring the bar back to starting position as your breathe in.", "Repeat for the recommended amount of repetitions."] },
  "바벨 스쿼트": { s: "Barbell_Squat/0.jpg", e: "Barbell_Squat/1.jpg", k: ["이 운동은 안전을 위해 스쿼트 랙 안에서 하는 것이 가장 좋습니다. 먼저 바를 어깨보다 살짝 아래 높이의 랙에 겁니다. 높이를 맞추고 무게를 걸었으면 바 아래로 들어가 어깨 뒤쪽(목보다 살짝 아래)에 바를 얹습니다.", "양팔로 바 양쪽을 잡고, 다리로 밀면서 동시에 상체를 세워 바를 랙에서 들어올립니다.", "랙에서 물러나 발끝을 살짝 바깥으로 향한 어깨너비의 중간 스탠스로 다리를 벌립니다. 머리는 항상 들고 등은 곧게 유지하세요. 이 자세가 시작 자세입니다. (참고: 여기서는 전반적 발달을 목표로 하는 위 중간 스탠스를 기준으로 설명하지만, 발 스탠스 항목에서 다룬 세 가지 스탠스 중 어느 것이든 선택할 수 있습니다.)", "머리를 든 곧은 자세를 유지하며 무릎과 고관절을 굽혀 바를 천천히 내리기 시작합니다. 허벅지와 종아리 사이 각도가 90도보다 조금 작아질 때까지 내립니다. 이 동작을 하며 숨을 들이마십니다. 팁: 올바로 수행했다면 무릎 앞이 발끝과 정면에 수직인 가상의 직선을 이뤄야 합니다. 무릎이 그 선을 넘어가면(발끝을 넘어가면) 무릎에 과도한 부담이 가는 것으로 잘못 수행한 것입니다.", "숨을 내쉬며 발뒤꿈치로 바닥을 밀어 다리를 다시 펴면서 바를 들어올려 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack to just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.", "Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.", "Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).", "Begin to slowly lower the bar by bending the knees and hips as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.", "Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "프론트 스쿼트": { s: "Front_Barbell_Squat/0.jpg", e: "Front_Barbell_Squat/1.jpg", k: ["이 운동은 안전을 위해 스쿼트 랙 안에서 하는 것이 가장 좋습니다. 먼저 자신의 키에 가장 잘 맞는 높이의 랙에 바를 겁니다. 높이를 맞추고 무게를 걸었으면 팔꿈치를 높이 들고 위팔을 바닥과 평행보다 살짝 위로 유지한 채 바 아래로 팔을 넣습니다. 바를 삼각근 위에 얹고, 완전히 제어하기 위해 팔을 교차해 바를 잡습니다.", "다리로 밀면서 동시에 상체를 세워 바를 랙에서 들어올립니다.", "랙에서 물러나 발끝을 살짝 바깥으로 향한 어깨너비의 중간 스탠스로 다리를 벌립니다. 아래를 보면 균형을 잃으니 머리는 항상 들고 등은 곧게 유지하세요. 이 자세가 시작 자세입니다. (참고: 여기서는 전반적 발달을 목표로 하는 위 중간 스탠스를 기준으로 설명하지만, 발 위치 항목에서 다룬 세 가지 스탠스 중 어느 것이든 선택할 수 있습니다.)", "머리를 든 곧은 자세를 유지하며 무릎을 굽혀 바를 천천히 내리기 시작합니다. 허벅지와 종아리 사이 각도가 90도보다 조금 작아질 때까지(허벅지가 바닥과 평행보다 아래로 내려가는 지점) 내립니다. 이 동작을 하며 숨을 들이마십니다. 팁: 올바로 수행했다면 무릎 앞이 발끝과 정면에 수직인 가상의 직선을 이뤄야 합니다. 무릎이 그 선을 넘어가면(발끝을 넘어가면) 무릎에 과도한 부담이 가는 것으로 잘못 수행한 것입니다.", "숨을 내쉬며 주로 발 중앙으로 바닥을 밀어 다리를 다시 펴면서 바를 들어올려 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, bring your arms up under the bar while keeping the elbows high and the upper arm slightly above parallel to the floor. Rest the bar on top of the deltoids and cross your arms while grasping the bar for total control.", "Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso.", "Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).", "Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.", "Begin to raise the bar as you exhale by pushing the floor mainly with the middle of your foot as you straighten the legs again and go back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "하이바 스쿼트": { s: "Barbell_Squat/0.jpg", e: "Barbell_Squat/1.jpg", k: ["이 운동은 안전을 위해 스쿼트 랙 안에서 하는 것이 가장 좋습니다. 먼저 바를 어깨보다 살짝 아래 높이의 랙에 겁니다. 높이를 맞추고 무게를 걸었으면 바 아래로 들어가 어깨 뒤쪽(목보다 살짝 아래)에 바를 얹습니다.", "양팔로 바 양쪽을 잡고, 다리로 밀면서 동시에 상체를 세워 바를 랙에서 들어올립니다.", "랙에서 물러나 발끝을 살짝 바깥으로 향한 어깨너비의 중간 스탠스로 다리를 벌립니다. 머리는 항상 들고 등은 곧게 유지하세요. 이 자세가 시작 자세입니다. (참고: 여기서는 전반적 발달을 목표로 하는 위 중간 스탠스를 기준으로 설명하지만, 발 스탠스 항목에서 다룬 세 가지 스탠스 중 어느 것이든 선택할 수 있습니다.)", "머리를 든 곧은 자세를 유지하며 무릎과 고관절을 굽혀 바를 천천히 내리기 시작합니다. 허벅지와 종아리 사이 각도가 90도보다 조금 작아질 때까지 내립니다. 이 동작을 하며 숨을 들이마십니다. 팁: 올바로 수행했다면 무릎 앞이 발끝과 정면에 수직인 가상의 직선을 이뤄야 합니다. 무릎이 그 선을 넘어가면(발끝을 넘어가면) 무릎에 과도한 부담이 가는 것으로 잘못 수행한 것입니다.", "숨을 내쉬며 발뒤꿈치로 바닥을 밀어 다리를 다시 펴면서 바를 들어올려 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack to just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.", "Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.", "Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).", "Begin to slowly lower the bar by bending the knees and hips as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.", "Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "핵 스쿼트": { s: "Hack_Squat/0.jpg", e: "Hack_Squat/1.jpg", k: ["상체 뒤쪽을 머신의 등받이 패드에 대고 어깨를 어깨 패드 아래에 겁니다.", "발끝을 살짝 바깥으로 향한 어깨너비의 중간 스탠스로 발판에 다리를 놓습니다. 팁: 머리는 항상 들고 등은 항상 패드에 붙여 유지하세요.", "팔을 머신 옆쪽 손잡이에 얹고 안전바를 해제합니다(대부분의 기종에서는 옆 손잡이를 정면 위치에서 대각선 위치로 돌려 해제합니다).", "이제 무릎을 완전히 잠그지 않은 채 다리를 폅니다. 이 자세가 시작 자세입니다. (참고: 여기서는 전반적 발달을 목표로 하는 위 중간 스탠스를 기준으로 설명하지만, 발 위치 항목에서 다룬 세 가지 스탠스 중 어느 것이든 선택할 수 있습니다.)", "머리를 들고(등은 항상 패드에 붙인 채) 곧은 자세를 유지하며 무릎을 굽혀 기구를 천천히 내리기 시작합니다. 허벅지와 종아리 사이 각도가 90도보다 조금 작아질 때까지(허벅지가 바닥과 평행보다 아래로 내려가는 지점) 내립니다. 이 동작을 하며 숨을 들이마십니다. 팁: 올바로 수행했다면 무릎 앞이 발끝과 정면에 수직인 가상의 직선을 이뤄야 합니다. 무릎이 그 선을 넘어가면(발끝을 넘어가면) 무릎에 과도한 부담이 가는 것으로 잘못 수행한 것입니다.", "숨을 내쉬며 주로 발뒤꿈치로 발판을 밀어 다리를 다시 펴면서 기구를 올려 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.", "Position your legs in the platform using a shoulder width medium stance with the toes slightly pointed out. Tip: Keep your head up at all times and also maintain the back on the pad at all times.", "Place your arms on the side handles of the machine and disengage the safety bars (which on most designs is done by moving the side handles from a facing front position to a diagonal position).", "Now straighten your legs without locking the knees. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).", "Begin to slowly lower the unit by bending the knees as you maintain a straight posture with the head up (back on the pad at all times). Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.", "Begin to raise the unit as you exhale by pushing the floor with mainly with the heel of your foot as you straighten the legs again and go back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "레그 프레스": { s: "Leg_Press/0.jpg", e: "Leg_Press/1.jpg", k: ["레그 프레스 머신에 앉아 발을 어깨너비의 중간 스탠스로 바로 앞 발판에 놓습니다. (참고: 여기서는 전반적 발달을 목표로 하는 위 중간 스탠스를 기준으로 설명하지만, 발 위치 항목에서 다룬 세 가지 스탠스 중 어느 것이든 선택할 수 있습니다.)", "무게가 실린 발판을 고정하는 안전바를 내리고, 다리가 앞으로 완전히 펴질 때까지 발판을 끝까지 밀어 올립니다. 팁: 무릎을 완전히 잠그지 마세요. 상체와 다리가 정확히 90도 각도를 이뤄야 합니다. 이 자세가 시작 자세입니다.", "숨을 들이마시며 허벅지와 종아리가 90도 각도를 이룰 때까지 발판을 천천히 내립니다.", "숨을 내쉬며 주로 발뒤꿈치로 밀고 대퇴사두를 사용해 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 반복하고, 끝나면 안전핀을 반드시 제대로 잠그세요. 무게가 가득 실린 발판이 몸 위로 떨어지면 안 됩니다."], en: ["Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).", "Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.", "As you inhale, slowly lower the platform until your upper and lower legs make a 90-degree angle.", "Pushing mainly with the heels of your feet and using the quadriceps go back to the starting position as you exhale.", "Repeat for the recommended amount of repetitions and ensure to lock the safety pins properly once you are done. You do not want that platform falling on you fully loaded."] },
  "레그 익스텐션": { s: "Leg_Extensions/0.jpg", e: "Leg_Extensions/1.jpg", k: ["이 운동은 레그 익스텐션 머신을 사용합니다. 먼저 무게를 고른 뒤 다리를 패드 아래(발끝은 앞을 향함)에 두고 옆 손잡이를 잡은 채 머신에 앉습니다. 이 자세가 시작 자세입니다. 팁: 패드가 정강이 위쪽(발 바로 위)에 오도록 조절하세요. 또한 종아리와 허벅지가 90도 각도를 이루도록 하세요. 각도가 90도보다 작으면 무릎이 발끝을 넘어간다는 뜻이며 무릎 관절에 과도한 부담을 줍니다. 머신이 그렇게 설계돼 있다면 다른 머신을 찾거나, 운동 시작 시 90도에 도달하면 더 내려가지 않도록 하세요.", "숨을 내쉬며 대퇴사두를 사용해 다리를 최대한 폅니다. 나머지 몸은 시트에 고정된 채로 유지하세요. 수축 지점에서 1초간 멈춥니다.", "숨을 들이마시며 무게를 천천히 원래 위치로 내립니다. 90도 각도 한계를 넘지 않도록 하세요.", "권장 반복 횟수만큼 반복합니다."], en: ["For this exercise you will need to use a leg extension machine. First choose your weight and sit on the machine with your legs under the pad (feet pointed forward) and the hands holding the side bars. This will be your starting position. Tip: You will need to adjust the pad so that it falls on top of your lower leg (just above your feet). Also, make sure that your legs form a 90-degree angle between the lower and upper leg. If the angle is less than 90-degrees then that means the knee is over the toes which in turn creates undue stress at the knee joint. If the machine is designed that way, either look for another machine or just make sure that when you start executing the exercise you stop going down once you hit the 90-degree angle.", "Using your quadriceps, extend your legs to the maximum as you exhale. Ensure that the rest of the body remains stationary on the seat. Pause a second on the contracted position.", "Slowly lower the weight back to the original position as you inhale, ensuring that you do not go past the 90-degree angle limit.", "Repeat for the recommended amount of times."] },
  "고블릿 스쿼트": { s: "Goblet_Squat/0.jpg", e: "Goblet_Squat/1.jpg", k: ["가벼운 케틀벨의 뿔(손잡이 양옆)을 잡아 가슴 가까이 든 채 섭니다. 이 자세가 시작 자세입니다.", "허벅지 뒤가 종아리에 닿을 때까지 다리 사이로 앉아 내려갑니다. 가슴과 머리는 들고 등은 곧게 유지하세요.", "맨 아래 지점에서 잠시 멈추고 팔꿈치로 무릎을 바깥으로 밀어줍니다. 시작 자세로 돌아가 10~20회 반복합니다."], en: ["Stand holding a light kettlebell by the horns close to your chest. This will be your starting position.", "Squat down between your legs until your hamstrings are on your calves. Keep your chest and head up and your back straight.", "At the bottom position, pause and use your elbows to push your knees out. Return to the starting position, and repeat for 10-20 repetitions."] },
  "런지": { s: "Dumbbell_Lunges/0.jpg", e: "Dumbbell_Lunges/1.jpg", k: ["상체를 곧게 세우고 양손에 덤벨을 들어 옆구리에 둔 채 섭니다. 이 자세가 시작 자세입니다.", "뒤에 고정된 발에서 약 60cm 앞으로 오른발을 내딛고, 상체를 곧게 세우고 균형을 유지한 채 몸을 낮춥니다. 내려가며 숨을 들이마십니다. 참고: 다른 운동과 마찬가지로 내려갈 때 무릎이 발끝을 넘어가지 않게 하세요. 무릎 관절에 과도한 부담을 줍니다. 앞쪽 정강이가 바닥과 수직이 되도록 유지하세요.", "숨을 내쉬며 주로 발뒤꿈치로 밀어 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 동작을 반복한 뒤 왼발로 수행합니다."], en: ["Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.", "Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.", "Using mainly the heel of your foot, push up and go back to the starting position as you exhale.", "Repeat the movement for the recommended amount of repetitions and then perform with the left leg."] },
  "워킹 런지": { s: "Bodyweight_Walking_Lunge/0.jpg", e: "Bodyweight_Walking_Lunge/1.jpg", k: ["발을 어깨너비로 벌리고 손을 허리에 얹은 채 섭니다.", "한쪽 다리를 앞으로 내딛으며 무릎을 굽혀 골반을 낮춥니다. 뒤쪽 무릎이 바닥에 거의 닿을 때까지 내려갑니다. 자세는 곧게 유지하고 앞쪽 무릎은 앞발 위에 오도록 합니다.", "앞발 뒤꿈치로 밀고 양 무릎을 펴 몸을 다시 일으킵니다.", "뒤쪽 발을 앞으로 내딛어 반대쪽 다리로 런지를 반복합니다."], en: ["Begin standing with your feet shoulder width apart and your hands on your hips.", "Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.", "Drive through the heel of your lead foot and extend both knees to raise yourself back up.", "Step forward with your rear foot, repeating the lunge on the opposite leg."] },
  "불가리안 스플릿 스쿼트": { s: "Split_Squat_with_Dumbbells/0.jpg", e: "Split_Squat_with_Dumbbells/1.jpg", k: ["뒷발을 높은 곳에 올리고 앞발을 앞으로 둔 스태거드 스탠스를 취합니다.", "양손에 덤벨을 들어 옆으로 늘어뜨립니다. 이 자세가 시작 자세입니다.", "무릎과 고관절을 굽혀 몸을 낮추며 내려가기 시작합니다. 동작 내내 바른 자세를 유지하세요. 운동하는 동안 앞쪽 무릎이 발과 일직선을 이루도록 유지합니다.", "맨 아래 지점에서 발뒤꿈치로 밀어 무릎과 고관절을 펴 시작 자세로 돌아갑니다."], en: ["Position yourself into a staggered stance with the rear foot elevated and front foot forward.", "Hold a dumbbell in each hand, letting them hang at the sides. This will be your starting position.", "Begin by descending, flexing your knee and hip to lower your body down. Maintain good posture througout the movement. Keep the front knee in line with the foot as you perform the exercise.", "At the bottom of the movement, drive through the heel to extend the knee and hip to return to the starting position."] },
  "스미스 스쿼트": { s: "Smith_Machine_Squat/0.jpg", e: "Smith_Machine_Squat/1.jpg", k: ["먼저 자신의 키에 가장 잘 맞는 높이에 바를 설정합니다. 높이를 맞추고 무게를 걸었으면 바 아래로 들어가 어깨 뒤쪽(목보다 살짝 아래)에 바를 얹습니다.", "양팔로 바 양쪽을 잡고(손바닥은 앞을 향함) 잠금을 풀어, 다리로 밀면서 동시에 상체를 세워 바를 랙에서 들어올립니다.", "발끝을 살짝 바깥으로 향한 어깨너비의 중간 스탠스로 다리를 벌립니다. 머리는 항상 들고 등은 곧게 유지하세요. 이 자세가 시작 자세입니다. (참고: 여기서는 전반적 발달을 목표로 하는 중간 스탠스를 기준으로 설명하지만, 발 스탠스 항목에서 다룬 세 가지 스탠스 중 어느 것이든 선택할 수 있습니다.)", "머리를 든 곧은 자세를 유지하며 무릎을 굽혀 바를 천천히 내리기 시작합니다. 허벅지와 종아리 사이 각도가 90도보다 조금 작아질 때까지(허벅지가 바닥과 평행보다 아래로 내려가는 지점) 내립니다. 이 동작을 하며 숨을 들이마십니다. 팁: 올바로 수행했다면 무릎 앞이 발끝과 정면에 수직인 가상의 직선을 이뤄야 합니다. 무릎이 그 선을 넘어가면(발끝을 넘어가면) 무릎에 과도한 부담이 가는 것으로 잘못 수행한 것입니다.", "숨을 내쉬며 발뒤꿈치로 바닥을 밀어 다리를 다시 펴면서 바를 들어올려 시작 자세로 돌아갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["To begin, first set the bar on the height that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.", "Hold on to the bar using both arms at each side (palms facing forward), unlock it and lift it off the rack by first pushing with your legs and at the same time straightening your torso.", "Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance which targets overall development; however you can choose any of the three stances discussed in the foot stances section).", "Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.", "Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "스텝업": { s: "Dumbbell_Step_Ups/0.jpg", e: "Dumbbell_Step_Ups/1.jpg", k: ["양손에 덤벨을 들고(손바닥은 다리 옆을 향함) 똑바로 섭니다.", "오른발을 높은 발판에 올립니다. 오른쪽 고관절과 무릎을 펴 발판 위로 올라섭니다. 주로 뒤꿈치로 나머지 몸을 밀어 올리며 왼발도 발판에 올립니다. 올라서는 힘을 쓸 때 숨을 내쉽니다.", "숨을 들이마시며 오른쪽 고관절과 무릎을 굽혀 왼발부터 내려딛습니다. 오른발을 처음 위치의 왼발 옆에 놓아 원래 서 있던 자세로 돌아갑니다.", "오른발로 권장 반복 횟수만큼 반복한 뒤 왼발로 수행합니다."], en: ["Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).", "Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up.", "Step down with the left leg by flexing the hip and knee of the right leg as you inhale. Return to the original standing position by placing the right foot of to next to the left foot on the initial position.", "Repeat with the right leg for the recommended amount of repetitions and then perform with the left leg."] },
  "루마니안 데드리프트": { s: "Romanian_Deadlift/0.jpg", e: "Romanian_Deadlift/1.jpg", k: ["바벨을 앞쪽 바닥에 두고 어깨너비보다 조금 넓게 오버핸드 그립(손바닥이 아래를 향함)으로 잡습니다. 팁: 사용하는 무게에 따라 손목 스트랩이 필요할 수 있고, 가동 범위를 넓히기 위해 높은 발판이 필요할 수도 있습니다.", "무릎을 살짝 굽히고 정강이를 수직으로 유지하며, 엉덩이를 뒤로 빼고 등을 곧게 폅니다. 이 자세가 시작 자세입니다.", "등과 팔을 항상 완전히 곧게 유지한 채 숨을 내쉬며 고관절을 사용해 바를 들어올립니다. 팁: 동작은 빠르게가 아니라 꾸준하고 통제된 상태로 해야 합니다.", "완전히 곧게 선 뒤에는 스쿼트와 달리 무릎은 살짝만 굽히고 엉덩이를 뒤로 밀며 바를 내립니다. 팁: 동작 시작 시 깊게 숨을 들이마시고 가슴을 편 상태를 유지하세요. 내리는 동안 숨을 참고 동작을 마칠 때 내쉽니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion.", "Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position.", "Keeping your back and arms completely straight at all times, use your hips to lift the bar as you exhale. Tip: The movement should not be fast but steady and under control.", "Once you are standing completely straight up, lower the bar by pushing the hips back, only slightly bending the knees, unlike when squatting. Tip: Take a deep breath at the start of the movement and keep your chest up. Hold your breath as you lower and exhale as you complete the movement.", "Repeat for the recommended amount of repetitions."] },
  "스티프 레그 데드리프트": { s: "Stiff-Legged_Barbell_Deadlift/0.jpg", e: "Stiff-Legged_Barbell_Deadlift/1.jpg", k: ["오버핸드 그립(손바닥이 아래를 향함)으로 바를 잡습니다. 상당한 무게를 사용한다면 손목 스트랩이 필요할 수 있습니다.", "상체를 곧게 세우고 어깨너비 또는 그보다 좁은 스탠스로 다리를 벌려 섭니다. 무릎은 살짝 굽힙니다. 이 자세가 시작 자세입니다.", "무릎을 고정한 채 등을 곧게 유지하며 고관절을 굽혀 바벨을 발등 위까지 내립니다. 바닥에서 무언가를 집으려는 것처럼 햄스트링에 스트레칭이 느껴질 때까지 계속 숙입니다. 이 동작을 하며 숨을 들이마십니다.", "고관절을 펴 상체를 다시 곧게 세워 시작 자세로 돌아갑니다. 이 동작을 하며 숨을 내쉽니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Grasp a bar using an overhand grip (palms facing down). You may need some wrist wraps if using a significant amount of weight.", "Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.", "Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the hips while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Inhale as you perform this movement.", "Start bringing your torso up straight again by extending your hips until you are back at the starting position. Exhale as you perform this movement.", "Repeat for the recommended amount of repetitions."] },
  "라잉 레그 컬": { s: "Lying_Leg_Curls/0.jpg", e: "Lying_Leg_Curls/1.jpg", k: ["레그 컬 머신의 레버를 자기 키에 맞게 조절하고, 머신에 엎드려 레버 패드를 종아리 조금 아래(다리 뒤쪽)에 오도록 위치시킨다. 팁: 평평한 것보다 각도가 있는 레그 컬 머신을 쓰는 편이 좋다. 각진 자세가 햄스트링 자극에 더 유리하다.", "상체를 벤치에 평평하게 붙인 채 다리를 완전히 편 상태에서 머신 양옆 손잡이를 잡는다. 발끝은 정면을 향하게 둔다(또는 발 위치 파트에서 설명한 나머지 두 자세를 써도 된다). 이것이 시작 자세다.", "숨을 내쉬면서 허벅지(윗다리)가 패드에서 들리지 않도록 하며 다리를 최대한 위로 감아올린다. 완전히 수축된 지점에 도달하면 1초간 유지한다.", "숨을 들이마시면서 다리를 처음 위치로 되돌린다. 권장 반복 횟수만큼 반복한다."], en: ["Adjust the machine lever to fit your height and lie face down on the leg curl machine with the pad of the lever on the back of your legs (just a few inches under the calves). Tip: Preferably use a leg curl machine that is angled as opposed to flat since an angled position is more favorable for hamstrings recruitment.", "Keeping the torso flat on the bench, ensure your legs are fully stretched and grab the side handles of the machine. Position your toes straight (or you can also use any of the other two stances described on the foot positioning section). This will be your starting position.", "As you exhale, curl your legs up as far as possible without lifting the upper legs from the pad. Once you hit the fully contracted position, hold it for a second.", "As you inhale, bring the legs back to the initial position. Repeat for the recommended amount of repetitions."] },
  "시티드 레그 컬": { s: "Seated_Leg_Curl/0.jpg", e: "Seated_Leg_Curl/1.jpg", k: ["머신 레버를 자기 키에 맞게 조절하고, 등을 등받이 패드에 붙인 채 머신에 앉는다.", "종아리 조금 아래(정강이 뒤 아랫부분)를 패드가 달린 레버 위에 올리고, 무릎 바로 위 허벅지에 랩 패드를 고정한다. 그런 다음 발끝을 정면으로 향한 채(또는 다른 두 자세를 써도 된다) 머신 양옆 손잡이를 잡고, 다리를 앞으로 완전히 편 상태로 둔다. 이것이 시작 자세다.", "숨을 내쉬면서 무릎을 굽혀 레버를 허벅지 뒤쪽으로 최대한 당긴다. 상체는 항상 고정된 상태를 유지한다. 수축된 자세를 1초간 유지한다.", "숨을 들이마시면서 천천히 시작 자세로 돌아온다.", "권장 반복 횟수만큼 반복한다."], en: ["Adjust the machine lever to fit your height and sit on the machine with your back against the back support pad.", "Place the back of lower leg on top of padded lever (just a few inches under the calves) and secure the lap pad against your thighs, just above the knees. Then grasp the side handles on the machine as you point your toes straight (or you can also use any of the other two stances) and ensure that the legs are fully straight right in front of you. This will be your starting position.", "As you exhale, pull the machine lever as far as possible to the back of your thighs by flexing at the knees. Keep your torso stationary at all times. Hold the contracted position for a second.", "Slowly return to the starting position as you breathe in.", "Repeat for the recommended amount of repetitions."] },
  "레그 컬": { s: "Lying_Leg_Curls/0.jpg", e: "Lying_Leg_Curls/1.jpg", k: ["레그 컬 머신의 레버를 자기 키에 맞게 조절하고, 머신에 엎드려 레버 패드를 종아리 조금 아래(다리 뒤쪽)에 오도록 위치시킨다. 팁: 평평한 것보다 각도가 있는 레그 컬 머신을 쓰는 편이 좋다. 각진 자세가 햄스트링 자극에 더 유리하다.", "상체를 벤치에 평평하게 붙인 채 다리를 완전히 편 상태에서 머신 양옆 손잡이를 잡는다. 발끝은 정면을 향하게 둔다(또는 발 위치 파트에서 설명한 나머지 두 자세를 써도 된다). 이것이 시작 자세다.", "숨을 내쉬면서 허벅지(윗다리)가 패드에서 들리지 않도록 하며 다리를 최대한 위로 감아올린다. 완전히 수축된 지점에 도달하면 1초간 유지한다.", "숨을 들이마시면서 다리를 처음 위치로 되돌린다. 권장 반복 횟수만큼 반복한다."], en: ["Adjust the machine lever to fit your height and lie face down on the leg curl machine with the pad of the lever on the back of your legs (just a few inches under the calves). Tip: Preferably use a leg curl machine that is angled as opposed to flat since an angled position is more favorable for hamstrings recruitment.", "Keeping the torso flat on the bench, ensure your legs are fully stretched and grab the side handles of the machine. Position your toes straight (or you can also use any of the other two stances described on the foot positioning section). This will be your starting position.", "As you exhale, curl your legs up as far as possible without lifting the upper legs from the pad. Once you hit the fully contracted position, hold it for a second.", "As you inhale, bring the legs back to the initial position. Repeat for the recommended amount of repetitions."] },
  "힙 쓰러스트": { s: "Barbell_Hip_Thrust/0.jpg", e: "Barbell_Hip_Thrust/1.jpg", k: ["벤치를 등 바로 뒤에 두고 바닥에 앉아서 시작한다. 무게를 건 바벨을 다리 위에 올려둔다. 두꺼운 바를 쓰거나 바에 패드를 대면 이 운동에서 오는 불편함을 크게 줄일 수 있다.", "바가 엉덩이 바로 위에 오도록 굴린 뒤, 벤치에 기대어 견갑골이 벤치 윗부분 근처에 오게 한다.", "발로 바닥을 밀어내며 엉덩이를 수직으로 밀어 올려 바를 들어올리면서 동작을 시작한다. 체중은 견갑골과 발로 지탱해야 한다. 최대한 밀어 올린 뒤, 동작을 반대로 하여 시작 자세로 돌아온다."], en: ["Begin seated on the ground with a bench directly behind you. Have a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise.", "Roll the bar so that it is directly above your hips, and lean back against the bench so that your shoulder blades are near the top of it.", "Begin the movement by driving through your feet, extending your hips vertically through the bar. Your weight should be supported by your shoulder blades and your feet. Extend as far as possible, then reverse the motion to return to the starting position."] },
  "글루트 브릿지": { s: "Barbell_Glute_Bridge/0.jpg", e: "Barbell_Glute_Bridge/1.jpg", k: ["무게를 건 바벨을 다리 위에 올린 채 바닥에 앉아서 시작한다. 두꺼운 바를 쓰거나 바에 패드를 대면 이 운동에서 오는 불편함을 크게 줄일 수 있다. 바가 엉덩이 바로 위에 오도록 굴린 뒤 바닥에 평평하게 눕는다.", "발뒤꿈치로 바닥을 밀어내며 엉덩이를 수직으로 밀어 올려 바를 들어올리면서 동작을 시작한다. 체중은 상부 등과 발뒤꿈치로 지탱해야 한다.", "최대한 밀어 올린 뒤, 동작을 반대로 하여 시작 자세로 돌아온다."], en: ["Begin seated on the ground with a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise. Roll the bar so that it is directly above your hips, and lay down flat on the floor.", "Begin the movement by driving through with your heels, extending your hips vertically through the bar. Your weight should be supported by your upper back and the heels of your feet.", "Extend as far as possible, then reverse the motion to return to the starting position."] },
  "케이블 킥백": { s: "One-Legged_Cable_Kickback/0.jpg", e: "One-Legged_Cable_Kickback/1.jpg", k: ["가죽 발목 스트랩을 낮은 케이블 도르래에 걸고 발목에 채운다.", "약 60cm(2피트) 거리에서 웨이트 스택을 마주보고 서서 철제 프레임을 잡아 몸을 지지한다.", "무릎과 엉덩이를 살짝 굽히고 복근을 조인 상태에서 숨을 내쉬며 둔근을 수축시켜 운동하는 다리를 반원을 그리듯 편하게 올라가는 최대한 높이까지 천천히 '차 올린다'. 팁: 완전히 뻗은 지점에서 최고 수축을 위해 둔근을 1초간 쥐어짠다.", "이제 케이블의 당김에 저항하며 운동하는 다리를 천천히 앞으로 가져와 시작 자세까지 돌아온다.", "권장 반복 횟수만큼 반복한다.", "다리를 바꿔 반대쪽도 같은 동작을 반복한다."], en: ["Hook a leather ankle cuff to a low cable pulley and then attach the cuff to your ankle.", "Face the weight stack from a distance of about two feet, grasping the steel frame for support.", "While keeping your knees and hips bent slightly and your abs tight, contract your glutes to slowly \"kick\" the working leg back in a semicircular arc as high as it will comfortably go as you breathe out. Tip: At full extension, squeeze your glutes for a second in order to achieve a peak contraction.", "Now slowly bring your working leg forward, resisting the pull of the cable until you reach the starting position.", "Repeat for the recommended amount of repetitions.", "Switch legs and repeat the movement for the other side."] },
  "힙 어브덕션 머신": { s: "Thigh_Abductor/0.jpg", e: "Thigh_Abductor/1.jpg", k: ["먼저 어브덕터 머신에 앉아 편한 무게를 선택한다. 다리를 제대로 위치시켰으면 양옆 손잡이를 잡는다. 허리 위쪽 상체 전체는 고정된 상태를 유지해야 한다. 이것이 시작 자세다.", "숨을 내쉬면서 다리로 머신을 천천히 밀어 양다리를 서로 바깥쪽으로 벌린다.", "1초간 수축을 느낀 뒤, 숨을 들이마시면서 다리를 시작 자세로 되돌리기 시작한다. 참고: 부상을 막기 위해 상체는 항상 고정된 상태를 유지한다.", "권장 반복 횟수만큼 반복한다."], en: ["To begin, sit down on the abductor machine and select a weight you are comfortable with. When your legs are positioned properly, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.", "Slowly press against the machine with your legs to move them away from each other while exhaling.", "Feel the contraction for a second and begin to move your legs back to the starting position while breathing in. Note: Remember to keep your upper body stationary to prevent any injuries from occurring.", "Repeat for the recommended amount of repetitions."] },
  "케틀벨 스윙": { s: "One-Arm_Kettlebell_Swings/0.jpg", e: "One-Arm_Kettlebell_Swings/1.jpg", k: [], en: [] },
  "스탠딩 카프 레이즈": { s: "Standing_Calf_Raises/0.jpg", e: "Standing_Calf_Raises/1.jpg", k: ["카프 레이즈 머신의 패드 레버를 자기 키에 맞게 조절한다.", "제공된 패드 아래에 어깨를 넣고 발끝이 정면을 향하게 둔다(또는 이 장 앞부분에서 설명한 다른 두 자세를 써도 된다). 발 앞꿈치를 카프 블록 위에 고정하고 발뒤꿈치는 블록 밖으로 나오게 한다. 엉덩이와 무릎을 펴서 레버를 밀어 올려 상체를 곧게 세운다. 무릎은 완전히 잠그지 말고 살짝 굽힌 상태를 유지한다. 발끝은 이 장 앞부분에서 설명한 대로 정면, 바깥쪽 또는 안쪽을 향하게 한다. 이것이 시작 자세다.", "숨을 내쉬면서 발목을 최대한 펴고 종아리를 수축시켜 발뒤꿈치를 들어 올린다. 무릎은 항상 고정된 상태를 유지한다. 어떤 순간에도 굽혀서는 안 된다. 수축된 자세를 1초간 유지한 뒤 내려가기 시작한다.", "숨을 들이마시면서 발목을 굽혀 발뒤꿈치를 종아리가 늘어날 때까지 내리며 천천히 시작 자세로 돌아온다.", "권장 반복 횟수만큼 반복한다."], en: ["Adjust the padded lever of the calf raise machine to fit your height.", "Place your shoulders under the pads provided and position your toes facing forward (or using any of the two other positions described at the beginning of the chapter). The balls of your feet should be secured on top of the calf block with the heels extending off it. Push the lever up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.", "Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.", "Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.", "Repeat for the recommended amount of repetitions."] },
  "시티드 카프 레이즈": { s: "Seated_Calf_Raise/0.jpg", e: "Seated_Calf_Raise/1.jpg", k: ["머신에 앉아 발끝을 제공된 발판의 아랫부분에 올리고 발뒤꿈치는 밖으로 나오게 한다. 이 장 앞부분에 따라 원하는 발끝 방향(정면, 안쪽, 바깥쪽)을 선택한다.", "허벅지 아랫부분을 레버 패드 아래에 넣는데, 이 패드는 허벅지 높이에 맞게 조절해야 한다. 이제 패드가 앞으로 미끄러지지 않도록 양손을 레버 패드 위에 올린다.", "발뒤꿈치를 밀어 올려 레버를 살짝 들어 올린 뒤 안전바를 푼다. 이것이 시작 자세다.", "발목을 굽혀 종아리가 완전히 늘어날 때까지 발뒤꿈치를 천천히 내린다. 이 동작을 하는 동안 숨을 들이마신다.", "숨을 내쉬며 종아리를 수축시켜 발목을 최대한 펴며 발뒤꿈치를 들어 올린다. 꼭대기에서 수축을 1초간 유지한다.", "권장 반복 횟수만큼 반복한다."], en: ["Sit on the machine and place your toes on the lower portion of the platform provided with the heels extending off. Choose the toe positioning of your choice (forward, in, or out) as per the beginning of this chapter.", "Place your lower thighs under the lever pad, which will need to be adjusted according to the height of your thighs. Now place your hands on top of the lever pad in order to prevent it from slipping forward.", "Lift the lever slightly by pushing your heels up and release the safety bar. This will be your starting position.", "Slowly lower your heels by bending at the ankles until the calves are fully stretched. Inhale as you perform this movement.", "Raise the heels by extending the ankles as high as possible as you contract the calves and breathe out. Hold the top contraction for a second.", "Repeat for the recommended amount of repetitions."] },
  "레그 프레스 카프 레이즈": { s: "Calf_Press_On_The_Leg_Press_Machine/0.jpg", e: "Calf_Press_On_The_Leg_Press_Machine/1.jpg", k: ["레그 프레스 머신에 앉아 두 발을 바로 앞의 발판에 어깨너비 정도로 벌려 올린다.", "무게가 실린 발판을 고정하던 안전바를 내리고, 무릎을 완전히 잠그지 않은 채 다리를 앞으로 완전히 펴질 때까지 발판을 끝까지 밀어 올린다. (참고: 일부 레그 프레스 기구는 안전을 위해 안전바를 걸어둔 채로 할 수 있다. 기구가 이를 허용한다면 이 방식으로 운동하는 편이 좋다.) 상체와 다리는 정확히 90도를 이뤄야 한다. 이제 발끝과 발 앞꿈치를 발판 아랫부분에 조심스럽게 올리고 발뒤꿈치는 밖으로 나오게 한다. 발끝은 이 장 앞부분에서 설명한 대로 정면, 바깥쪽 또는 안쪽을 향하게 한다. 이것이 시작 자세다.", "숨을 내쉬면서 발목을 최대한 펴고 종아리를 수축시켜 발뒤꿈치를 들어 올려 발판을 민다. 무릎은 항상 고정된 상태를 유지한다. 어떤 순간에도 굽혀서는 안 된다. 수축된 자세를 1초간 유지한 뒤 내려가기 시작한다.", "숨을 들이마시면서 발목을 굽혀 발뒤꿈치를 종아리가 늘어날 때까지 내리며 천천히 시작 자세로 돌아온다.", "권장 반복 횟수만큼 반복한다."], en: ["Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance.", "Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you without locking your knees. (Note: In some leg press units you can leave the safety bars on for increased safety. If your leg press unit allows for this, then this is the preferred method of performing the exercise.) Your torso and the legs should make perfect 90-degree angle. Now carefully place your toes and balls of your feet on the lower portion of the platform with the heels extending off. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.", "Press on the platform by raising your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.", "Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.", "Repeat for the recommended amount of repetitions."] },
  "덤벨 카프 레이즈": { s: "Standing_Dumbbell_Calf_Raise/0.jpg", e: "Standing_Dumbbell_Calf_Raise/1.jpg", k: ["상체를 곧게 세우고 양손에 덤벨을 들어 몸 옆에 둔다. 발 앞꿈치를 튼튼하고 안정적인 나무판(약 5~8cm 높이) 위에 올리고 발뒤꿈치는 밖으로 나와 바닥에 닿게 한다. 이것이 시작 자세다.", "발끝을 정면(모든 부위를 고르게 자극), 안쪽(바깥쪽 종아리 강조), 또는 바깥쪽(안쪽 종아리 강조)으로 향한 채, 숨을 내쉬며 종아리를 수축시켜 발뒤꿈치를 바닥에서 들어 올린다. 꼭대기에서 수축을 1초간 유지한다.", "숨을 들이마시면서 발뒤꿈치를 천천히 내려 시작 자세로 돌아온다.", "권장 횟수만큼 반복한다."], en: ["Stand with your torso upright holding two dumbbells in your hands by your sides. Place the ball of the foot on a sturdy and stable wooden board (that is around 2-3 inches tall) while your heels extend off and touch the floor. This will be your starting position.", "With the toes pointing either straight (to hit all parts equally), inwards (for emphasis on the outer head) or outwards (for emphasis on the inner head), raise the heels off the floor as you exhale by contracting the calves. Hold the top contraction for a second.", "As you inhale, go back to the starting position by slowly lowering the heels.", "Repeat for the recommended amount of times."] },
  "플랭크": { s: "Plank/0.jpg", e: "Plank/1.jpg", k: ["바닥에 엎드린 자세를 취하고 발끝과 팔뚝으로 체중을 지지한다. 팔은 굽혀 어깨 바로 아래에 오게 한다.", "몸을 항상 일직선으로 유지한 채 가능한 한 오래 이 자세를 버틴다. 난이도를 높이려면 팔이나 다리를 하나 들어 올린다."], en: ["Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.", "Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised."] },
  "사이드 플랭크": { s: "Side_Bridge/0.jpg", e: "Side_Bridge/1.jpg", k: [], en: [] },
  "크런치": { s: "Crunches/0.jpg", e: "Crunches/1.jpg", k: ["등을 바닥에 대고 평평하게 누워 발을 바닥에 붙이거나, 무릎을 90도로 굽혀 벤치 위에 올린다. 발을 벤치에 올리는 경우 8~10cm 정도 벌리고 발끝을 안쪽으로 모아 서로 닿게 한다.", "이제 팔꿈치를 안으로 모은 채 양손을 머리 양옆에 가볍게 댄다. 팁: 손가락을 머리 뒤에서 깍지 끼지 않는다.", "복근을 더 잘 고립시키기 위해 허리를 바닥으로 눌러 붙이면서 어깨를 바닥에서 말아 올리기 시작한다.", "복근을 수축시키고 숨을 내쉬면서 허리로 최대한 세게 바닥을 눌러준다. 어깨는 바닥에서 약 10cm 정도만 들리고 허리는 바닥에 붙어 있어야 한다. 동작의 꼭대기에서 복근을 강하게 수축시켜 1초간 유지한다. 팁: 반동을 쓰지 말고 느리고 통제된 동작에 집중한다.", "1초간 수축한 뒤, 숨을 들이마시면서 다시 천천히 시작 자세로 내려온다.", "권장 반복 횟수만큼 반복한다."], en: ["Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch.", "Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.", "While pushing the small of your back down in the floor to better isolate your abdominal muscles, begin to roll your shoulders off the floor.", "Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum.", "After the one second contraction, begin to come down slowly again to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."] },
  "바이시클 크런치": { s: "Air_Bike/0.jpg", e: "Air_Bike/1.jpg", k: ["허리를 바닥에 눌러 붙인 채 바닥에 평평하게 눕는다. 이 운동에서는 양손을 머리 옆에 둔다. 단, 동작 중 목에 무리가 가지 않도록 주의한다. 이제 어깨를 들어 크런치 자세를 취한다.", "무릎을 바닥과 수직이 되도록 들어 올리고, 정강이는 바닥과 평행하게 둔다. 이것이 시작 자세다.", "이제 동시에, 자전거 페달을 밟듯 천천히 오른쪽 다리를 앞으로 차내며 왼쪽 무릎을 몸쪽으로 당긴다. 숨을 내쉬면서 옆으로 크런치하여 오른쪽 팔꿈치를 왼쪽 무릎에 가까이 가져간다.", "숨을 들이마시면서 처음 자세로 돌아온다.", "숨을 내쉬며 다리를 반대로 움직여 왼쪽 팔꿈치를 오른쪽 무릎에 가까이 가져가며 반대쪽으로 크런치한다.", "이런 식으로 좌우를 번갈아, 양쪽 모두 권장 반복 횟수를 채울 때까지 계속한다."], en: ["Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position.", "Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position.", "Now simultaneously, slowly go through a cycle pedal motion kicking forward with the right leg and bringing in the knee of the left leg. Bring your right elbow close to your left knee by crunching to the side, as you breathe out.", "Go back to the initial position as you breathe in.", "Crunch to the opposite side as you cycle your legs and bring closer your left elbow to your right knee and exhale.", "Continue alternating in this manner until all of the recommended repetitions for each side have been completed."] },
  "행잉 레그 레이즈": { s: "Hanging_Leg_Raise/0.jpg", e: "Hanging_Leg_Raise/1.jpg", k: ["와이드 그립이나 미디엄 그립으로 턱걸이 바를 잡고 양팔을 머리 위로 완전히 뻗어 매달린다. 다리는 곧게 아래로 내리고 골반은 약간 뒤로 말아준다. 이것이 시작 자세다.", "상체와 다리가 90도를 이룰 때까지 다리를 들어 올린다. 이 동작을 하면서 숨을 내쉬고 수축을 1초 정도 유지한다.", "숨을 들이마시면서 천천히 시작 자세로 돌아온다.", "권장 반복 횟수만큼 반복한다."], en: ["Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.", "Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.", "Go back slowly to the starting position as you breathe in.", "Repeat for the recommended amount of repetitions."] },
  "리버스 크런치": { s: "Reverse_Crunch/0.jpg", e: "Reverse_Crunch/1.jpg", k: ["다리를 완전히 펴고 팔은 상체 옆에 두어 손바닥을 바닥에 댄 채 바닥에 눕는다. 운동 내내 팔은 고정된 상태를 유지해야 한다.", "허벅지가 바닥과 수직이 되도록 다리를 들어 올리고, 두 발은 모아 바닥과 평행하게 둔다. 이것이 시작 자세다.", "숨을 들이마시면서 골반을 뒤로 말고 엉덩이를 바닥에서 들어 올리며 다리를 상체 쪽으로 가져온다. 이 동작의 끝에서 무릎이 가슴에 닿게 된다.", "수축을 1초간 유지한 뒤, 숨을 내쉬면서 다리를 시작 자세로 되돌린다.", "권장 반복 횟수만큼 반복한다."], en: ["Lie down on the floor with your legs fully extended and arms to the side of your torso with the palms on the floor. Your arms should be stationary for the entire exercise.", "Move your legs up so that your thighs are perpendicular to the floor and feet are together and parallel to the floor. This is the starting position.", "While inhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the floor. At the end of this movement your knees will be touching your chest.", "Hold the contraction for a second and move your legs back to the starting position while exhaling.", "Repeat for the recommended amount of repetitions."] },
  "케이블 크런치": { s: "Cable_Crunch/0.jpg", e: "Cable_Crunch/1.jpg", k: ["로프가 달린 높은 도르래 아래에 무릎을 꿇고 앉는다.", "케이블 로프를 잡고 손이 얼굴 옆에 오도록 로프를 내린다.", "엉덩이를 살짝 굽혀 무게가 허리를 뒤로 젖히도록 둔다. 이것이 시작 자세다.", "엉덩이는 고정한 채 복근을 수축시키며 허리를 굽혀 팔꿈치가 허벅지 가운데를 향해 내려가도록 한다. 이 부분의 동작을 하는 동안 숨을 내쉬고 수축을 1초간 유지한다.", "숨을 들이마시면서 천천히 시작 자세로 돌아온다. 팁: 동작 내내 복근에 일정한 긴장을 유지한다. 또한 허리가 부담을 대신 감당할 만큼 무거운 무게를 고르지 않는다.", "권장 반복 횟수만큼 반복한다."], en: ["Kneel below a high pulley that contains a rope attachment.", "Grasp cable rope attachment and lower the rope until your hands are placed next to your face.", "Flex your hips slightly and allow the weight to hyperextend the lower back. This will be your starting position.", "With the hips stationary, flex the waist as you contract the abs so that the elbows travel towards the middle of the thighs. Exhale as you perform this portion of the movement and hold the contraction for a second.", "Slowly return to the starting position as you inhale. Tip: Make sure that you keep constant tension on the abs throughout the movement. Also, do not choose a weight so heavy that the lower back handles the brunt of the work.", "Repeat for the recommended amount of repetitions."] },
  "러시안 트위스트": { s: "Russian_Twist/0.jpg", e: "Russian_Twist/1.jpg", k: ["움직이지 않는 것 아래에 발을 넣거나 파트너가 발을 잡아주게 하여 바닥에 눕는다. 다리는 무릎에서 굽힌다.", "상체를 들어 허벅지와 상상의 V자를 이루게 한다. 팔은 상체와 수직으로 앞으로 완전히 뻗고 양손은 맞잡는다. 이것이 시작 자세다.", "숨을 내쉬면서 팔이 바닥과 평행해질 때까지 상체를 오른쪽으로 비튼다.", "수축을 1초간 유지한 뒤 숨을 내쉬면서 시작 자세로 돌아온다. 이제 오른쪽에 적용한 것과 같은 방법으로 반대쪽으로 움직인다.", "권장 반복 횟수만큼 반복한다."], en: ["Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.", "Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position.", "Twist your torso to the right side until your arms are parallel with the floor while breathing out.", "Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side.", "Repeat for the recommended amount of repetitions."] },
  "앱 휠 롤아웃": { s: "Ab_Roller/0.jpg", e: "Ab_Roller/1.jpg", k: ["양손으로 앱 롤러를 잡고 바닥에 무릎을 꿇는다.", "이제 앱 롤러를 앞쪽 바닥에 두어 무릎 꿇은 푸시업 자세처럼 양손과 무릎으로 바닥을 짚는다. 이것이 시작 자세다.", "앱 롤러를 앞으로 천천히 굴려 몸을 일직선으로 뻗는다. 팁: 몸이 바닥에 닿지 않는 선에서 최대한 낮게 내려간다. 이 부분의 동작에서 숨을 들이마신다.", "뻗은 자세에서 잠시 멈춘 뒤, 숨을 내쉬면서 몸을 시작 자세로 다시 당겨온다. 팁: 천천히 하고 복근을 항상 조인 상태로 유지한다."], en: ["Hold the Ab Roller with both hands and kneel on the floor.", "Now place the ab roller on the floor in front of you so that you are on all your hands and knees (as in a kneeling push up position). This will be your starting position.", "Slowly roll the ab roller straight forward, stretching your body into a straight position. Tip: Go down as far as you can without touching the floor with your body. Breathe in during this portion of the movement.", "After a pause at the stretched position, start pulling yourself back to the starting position as you breathe out. Tip: Go slowly and keep your abs tight at all times."] },
  "디클라인 싯업": { s: "Sit-Up/0.jpg", e: "Sit-Up/1.jpg", k: ["움직이지 않는 것 아래에 발을 넣거나 파트너가 발을 잡아주게 하여 바닥에 눕는다. 다리는 무릎에서 굽힌다.", "양손을 머리 뒤에 대고 손가락을 깍지 껴 맞잡는다. 이것이 시작 자세다.", "상체를 들어 허벅지와 상상의 V자를 이루게 한다. 이 부분의 동작을 할 때 숨을 내쉰다.", "1초간 수축을 느끼면, 숨을 들이마시면서 상체를 다시 시작 자세로 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.", "Place your hands behind your head and lock them together by clasping your fingers. This is the starting position.", "Elevate your upper body so that it creates an imaginary V-shape with your thighs. Breathe out when performing this part of the exercise.", "Once you feel the contraction for a second, lower your upper body back down to the starting position while inhaling.", "Repeat for the recommended amount of repetitions."] },
  "마운틴 클라이머": { s: "Mountain_Climbers/0.jpg", e: "Mountain_Climbers/1.jpg", k: ["양손과 발끝으로 체중을 지지하는 푸시업 자세에서 시작한다. 무릎과 엉덩이를 굽혀 한쪽 다리를 무릎이 엉덩이 아래 근처에 올 때까지 당긴다. 이것이 시작 자세다.", "폭발적으로 두 다리의 위치를 바꿔, 굽힌 다리를 곧게 펴 발끝으로 지지하고 다른 발은 엉덩이와 무릎을 굽혀 앞으로 당긴다. 20~30초간 번갈아 반복한다."], en: ["Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position.", "Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds."] },
  "바벨 슈러그": { s: "Barbell_Shrug/0.jpg", e: "Barbell_Shrug/1.jpg", k: ["발을 어깨너비로 벌려 곧게 서서 오버핸드 그립(손바닥이 허벅지를 향함)으로 바벨을 양손으로 앞에 든다. 팁: 손은 어깨너비보다 약간 넓게 잡는다. 더 나은 그립을 위해 손목 랩을 사용해도 된다. 이것이 시작 자세다.", "숨을 내쉬면서 어깨를 최대한 높이 들어 올리고 수축을 1초간 유지한다. 팁: 이두근을 써서 바벨을 들어 올리려 하지 않는다.", "숨을 들이마시면서 천천히 시작 자세로 돌아온다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand up straight with your feet at shoulder width as you hold a barbell with both hands in front of you using a pronated grip (palms facing the thighs). Tip: Your hands should be a little wider than shoulder width apart. You can use wrist wraps for this exercise for a better grip. This will be your starting position.", "Raise your shoulders up as far as you can go as you breathe out and hold the contraction for a second. Tip: Refrain from trying to lift the barbell by using your biceps.", "Slowly return to the starting position as you breathe in.", "Repeat for the recommended amount of repetitions."] },
  "덤벨 슈러그": { s: "Dumbbell_Shrug/0.jpg", e: "Dumbbell_Shrug/1.jpg", k: ["양손에 덤벨을 하나씩 들고(손바닥이 몸통을 향함) 팔을 옆으로 뻗은 채 곧게 선다.", "숨을 내쉬면서 어깨를 최대한 높이 들어 올려 덤벨을 든다. 꼭대기에서 수축을 1초간 유지한다. 팁: 팔은 항상 뻗은 상태를 유지한다. 이두근을 써서 덤벨을 들어 올리지 않는다. 어깨만 위아래로 움직여야 한다.", "덤벨을 원래 위치로 내린다.", "권장 반복 횟수만큼 반복한다."], en: ["Stand erect with a dumbbell on each hand (palms facing your torso), arms extended on the sides.", "Lift the dumbbells by elevating the shoulders as high as possible while you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the dumbbells. Only the shoulders should be moving up and down.", "Lower the dumbbells back to the original position.", "Repeat for the recommended amount of repetitions."] },
  "바벨 클린": { s: "Power_Clean/0.jpg", e: "Power_Clean/1.jpg", k: ["발을 어깨너비보다 약간 넓게 벌리고 발끝을 살짝 바깥쪽으로 향하게 하여 선다.", "스쿼트 자세로 앉아 클로즈드 오버핸드 그립으로 바를 잡는다. 손은 무릎 바깥쪽에서 어깨너비보다 약간 넓게 잡고 팔꿈치는 완전히 편다.", "바를 정강이 앞 약 2.5cm(1인치) 지점, 발 앞꿈치 위에 위치시킨다.", "등은 평평하거나 약간 아치를 이루고, 가슴은 들어 내밀며 견갑골은 뒤로 모아야 한다.", "머리는 중립 자세(척추와 일직선, 기울이거나 돌리지 않음)로 유지하고 시선은 정면을 향한다. 이 단계에서 숨을 들이마신다.", "숨을 내쉬면서 엉덩이와 무릎을 힘차게 펴서 바를 바닥에서 들어 올린다. 팁: 상체는 같은 각도를 유지해야 한다. 아직 허리를 굽히지 말고, 어깨보다 엉덩이가 먼저 올라가지 않도록 한다(그러면 엉덩이가 위로 솟고 햄스트링이 늘어나게 된다).", "팔꿈치를 완전히 편 상태로 머리는 중립으로 유지하고 어깨는 바 위에 둔다.", "바가 올라갈 때 정강이에 최대한 가깝게 유지한다.", "바가 무릎을 지나면 엉덩이를 앞으로 밀고 무릎을 살짝 굽혀 잠기지 않게 한다. 팁: 이 시점에서 허벅지가 바에 닿아야 한다.", "등은 평평하거나 약간 아치를 이루고, 팔꿈치는 완전히 펴며 머리는 중립으로 유지한다. 팁: 다음 단계까지 숨을 참는다.", "숨을 들이마신 뒤 엉덩이와 무릎을 힘차고 빠르게 펴며 발끝으로 선다.", "바를 몸에 최대한 가깝게 유지한다. 팁: 등은 평평하게, 팔꿈치는 옆으로 향하게 하고 머리는 중립으로 둔다. 또한 어깨를 바 위에 두고 팔을 최대한 오래 곧게 유지한다.", "하체 관절이 완전히 펴지면 팔꿈치를 아직 굽히지 않은 채 어깨를 빠르게 위로 으쓱 들어 올린다. 이 부분의 동작에서 숨을 내쉰다.", "어깨가 가장 높이 올라가면 팔꿈치를 굽혀 몸을 바 아래로 당기기 시작한다.", "팔을 최대한 높고 오래 계속 당긴다. 팁: 이 단계의 폭발적인 특성 때문에 상체는 곧게 서거나 등이 아치를 이루고, 머리는 살짝 뒤로 젖혀지며 발이 바닥에서 떨어질 수도 있다.", "하체가 완전히 펴지고 바가 최대 높이 근처에 도달하면, 몸을 바 아래로 당기고 팔을 바 주위로 돌려 바 아래로 넣는다.", "동시에 엉덩이와 무릎을 굽혀 쿼터 스쿼트 자세를 취한다.", "팔이 바 아래에 오면 숨을 들이마신 뒤 팔꿈치를 들어 올려 상완이 바닥과 평행하게 위치시킨다. 바를 쇄골과 앞쪽 어깨 근육 앞에 걸쳐 랙 포지션을 만든다.", "상체를 곧고 단단히 세우고 머리는 중립, 발은 평평하게 붙인 채 바를 받아낸다. 이 동작에서 숨을 내쉰다.", "엉덩이와 무릎을 펴서 완전히 곧게 선 자세로 일어선다.", "팔의 근긴장을 서서히 풀어 바를 통제된 상태로 허벅지까지 내린다. 이 동작에서 숨을 들이마신다.", "동시에 엉덩이와 무릎을 굽혀 바가 허벅지에 닿는 충격을 완화한다.", "팔꿈치를 완전히 편 채 바가 바닥에 닿을 때까지 스쿼트 자세로 앉는다.", "1단계부터 다시 시작하여 권장 반복 횟수만큼 반복한다."], en: ["Stand with your feet slightly wider than shoulder width apart and toes pointing out slightly.", "Squat down and grasp bar with a closed, pronated grip. Your hands should be slightly wider than shoulder width apart outside knees with elbows fully extended.", "Place the bar about 1 inch in front of your shins and over the balls of your feet.", "Your back should be flat or slightly arched, your chest held up and out and your shoulder blades should be retracted.", "Keep your head in a neutral position (in line with vertebral column and not tilted or rotated) with your eyes focused straight ahead. Inhale during this phase.", "Lift the bar from the floor by forcefully extending the hips and the knees as you exhale. Tip: The upper torso should maintain the same angle. Do not bend at the waist yet and do not let the hips rise before the shoulders (this would have the effect of pushing the glutes in the air and stretching the hamstrings.", "Keep elbows fully extended with the head in a neutral position and the shoulders over the bar.", "As the bar raises keep it as close to the shins as possible.", "As the bar passes the knees, thrust your hips forward and slightly bend the knees to avoid locking them. Tip: At this point your thighs should be against the bar.", "Keep the back flat or slightly arched, elbows fully extended and your head neutral. Tip: You will hold your breath until the next phase.", "Inhale and then forcefully and quickly extend your hips and knees and stand on your toes.", "Keep the bar as close to your body as possible. Tip: Your back should be flat with the elbows pointed out to the sides and your head in a neutral position. Also, keep your shoulders over the bar and arms straight as long as possible.", "When your lower body joints are fully extended, shrug the shoulders upward rapidly without letting the elbows flex yet. Exhale during this portion of the movement.", "As the shoulders reach their highest elevation flex your elbows to begin pulling your body under the bar.", "Continue to pull the arms as high and as long as possible. Tip: Due to the explosive nature of this phase, your torso will be erect or with an arched back, your head will be tilted back slightly and your feet may lose contact with the floor.", "After the lower body has fully extended and the bar reaches near maximal height, pull your body under the bar and rotate the arms around and under the bar.", "Simultaneously, flex the hips and knees into a quarter squat position.", "Once the arms are under the bar, inhale and then lift your elbows to position the upper arms parallel to the floor. Rack the bar across the front of your collar bones and front shoulder muscles.", "Catch the bar with an erect and tight torso, a neutral head position and flat feet. Exhale during this movement.", "Stand up by extending the hips and knees to a fully erect position.", "Lower the bar by gradually reducing the muscular tension of the arms to allow a controlled descent of the bar to the thighs. Inhale during this movement.", "Simultaneously flex the hips and knees to cushion the impact of the bar on the thighs.", "Squat down with the elbows fully extended until the bar touches the floor.", "Start over at Phase 1 and repeat for the recommended amount of repetitions."] },
  "클린 앤 저크": { s: "Clean_and_Jerk/0.jpg", e: "Clean_and_Jerk/1.jpg", k: ["바벨을 정강이에 가깝게 바닥에 두고, 다리 바로 바깥쪽에서 오버핸드 그립 또는 훅 그립으로 잡습니다. 무게중심을 뒤꿈치에 두고 엉덩이를 낮추되, 허리는 곧게 펴고 시선은 정면을 향하며 가슴은 세우고 어깨가 바보다 살짝 앞으로 나오게 합니다. 이것이 시작 자세입니다.", "뒤꿈치로 바닥을 밀며 무릎을 펴 1차 당김(퍼스트 풀)을 시작합니다. 허리 각도는 그대로 유지하고 팔은 곧게 편 상태를 유지합니다. 무릎 위까지 계속 이어가면서 무게를 통제하며 들어 올립니다.", "다음은 클린의 주된 가속 구간인 2차 당김(세컨드 풀)입니다. 바가 허벅지 중간 위치에 도달하면 엉덩이를 펴기 시작합니다. 점프하는 동작처럼 엉덩이, 무릎, 발목을 펴며 속도를 이용해 바를 위로 가속시킵니다. 무게를 가속하기 위해 팔로 능동적으로 당길 필요는 없습니다. 2차 당김이 끝나는 지점에서 몸은 완전히 펴지고 약간 뒤로 기울며, 팔은 여전히 곧게 편 상태여야 합니다.", "완전히 신전되면 팔꿈치를 위·바깥으로 든 채 강하게 슈러그하고 팔을 굽히며 3차 당김(서드 풀)으로 전환합니다. 신전이 최고점에 이르면 몸을 강하게 아래로 당기면서 팔꿈치를 바 아래로 회전시킵니다. 프론트 스쿼트 자세로 바를 받아내며, 그 깊이는 3차 당김이 끝날 때 바의 높이에 따라 결정됩니다. 바는 앞으로 내민 어깨 위에 걸치듯 얹고, 손에 힘을 뺀 채 목에 가볍게 닿게 합니다. 계속 스쿼트 최저점까지 내려가면 일어서는 데 도움이 됩니다.", "곧바로 뒤꿈치로 밀며 상체를 세우고 팔꿈치를 든 채 일어섭니다. 완전히 선 자세가 될 때까지 이어갑니다.", "두 번째 단계는 무게를 머리 위로 들어 올리는 저크입니다. 무게를 어깨 앞쪽에 걸친 채 서서 딥 동작으로 시작합니다. 발을 엉덩이 바로 아래에 두고, 엉덩이를 뒤로 빼지 않은 채 무릎만 굽힙니다. 살짝만 내려간 뒤 최대한 힘차게 방향을 반대로 전환합니다.", "뒤꿈치로 밀며 최대한의 속도와 힘을 내고, 바가 어깨를 떠날 때 머리를 옆으로 피해 길을 비켜 줍니다.", "발이 바닥에서 떨어지는 이 순간, 발을 최대한 빠르게 받는 자세로 옮겨야 합니다. 발이 바닥을 능동적으로 밀지 않는 그 짧은 순간에, 바를 위로 밀어 올리려는 힘이 몸을 아래로 밀어 넣습니다. 발은 한쪽은 앞, 다른 쪽은 뒤로 갈라 벌립니다. 팔을 머리 위로 완전히 편 채 바를 받아냅니다. 그런 다음 선 자세로 돌아옵니다."], en: ["With a barbell on the floor close to the shins, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.", "Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.", "Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.", "As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.", "Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.", "The second phase is the jerk, which raises the weight overhead. Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible.", "Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.", "At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athletes effort to push the bar up will drive them down. The feet should be split, with one foot forward, and one foot back. Receive the bar with the arms locked out overhead. Return to a standing position."] },
  "스내치": { s: "Snatch/0.jpg", e: "Snatch/1.jpg", k: ["발을 어깨너비로 벌리고, 발가락과 발의 나머지 부분이 연결되는 지점 바로 위에 바벨이 오도록 섭니다.", "손바닥이 아래를 향하는 그립으로, 무릎을 굽히고 허리를 편평하게 유지한 채 어깨너비보다 넓게 바를 잡습니다. 엉덩이를 낮추고 의자에 앉듯 몸을 내립니다. 이것이 시작 자세입니다.", "발로 바닥을 움직이는 발판처럼 밀기 시작하면서 동시에 바벨을 다리에 가깝게 붙인 채 들어 올리기 시작합니다.", "바가 허벅지 중간에 도달하면 다리로 바닥을 밀며 몸을 폭발적으로 완전히 펴 올립니다.", "바를 위로 올리면서 슈러그하듯 어깨를 뒤로 들어 올리고, 팔꿈치를 옆으로 든 채 가능한 한 오래 바보다 높게 유지합니다.", "이제 매우 빠르지만 강한 동작으로, 바벨이 통제 가능할 만큼 충분히 높은 지점에 도달하면 몸을 바벨 아래로 넣고, 팔을 잠근 채 바벨을 머리 위로 든 상태로 스쿼트 자세를 취하며 내려갑니다.", "스쿼트 자세에서 일어서며 동작을 마무리합니다. 리프트가 끝날 때 두 발은 일직선상에 있고 팔은 완전히 펴 바벨을 머리 위로 든 상태여야 합니다."], en: ["Place your feet at a shoulder width stance with the barbell resting right above the connection between the toes and the rest of the foot.", "With a palms facing down grip, bend at the knees and keeping the back flat grab the bar using a wider than shoulder width grip. Bring the hips down and make sure that your body drops as if you were going to sit on a chair. This will be your starting position.", "Start pushing the floor as if it were a moving platform with your feet and simultaneously start lifting the barbell keeping it close to your legs.", "As the bar reaches the middle of your thighs, push the floor with your legs and lift your body to a complete extension in an explosive motion.", "Lift your shoulders back in a shrugging movement as you bring the bar up while lifting your elbows out to the side and keeping them above the bar for as long as possible.", "Now in a very quick but powerful motion, you have to get your body under the barbell when it has reached a high enough point where it can be controlled and drop while locking your arms and holding the barbell overhead as you assume a squat position.", "Finalize the movement by rising up out of the squat position to finish the lift. At the end of the lift both feet should be on line and the arms fully extended holding the barbell overhead."] },
  "배틀 로프": { s: "Battling_Ropes/0.jpg", e: "Battling_Ropes/1.jpg", k: ["이 운동에는 중앙이 4.5~6미터(15~20피트) 떨어진 곳에 고정된 무거운 로프가 필요합니다. 로프 앞에 서서 양손에 로프 끝을 하나씩 잡고 팔을 옆구리 옆으로 편 채 섭니다. 이것이 시작 자세입니다.", "한쪽 팔을 최대한 빠르게 어깨 높이까지 재빨리 들어 올리며 동작을 시작합니다.", "그 팔을 시작 자세로 떨어뜨리면서 반대쪽 팔을 들어 올립니다.", "좌우 팔을 번갈아 가며 최대한 빠르게 로프를 위아래로 후려칩니다."], en: ["For this exercise you will need a heavy rope anchored at its center 15-20 feet away. Standing in front of the rope, take an end in each hand with your arms extended at your side. This will be your starting position.", "Initiate the movement by rapidly raising one arm to shoulder level as quickly as you can.", "As you let that arm drop to the starting position, raise the opposite side.", "Continue alternating your left and right arms, whipping the ropes up and down as fast as you can."] },
  "로잉 머신": { s: "Rowing_Stationary/0.jpg", e: "Rowing_Stationary/1.jpg", k: ["먼저 로잉 머신에 앉습니다. 뒤꿈치가 발판 바닥에 편안히 닿고 스트랩이 고정되었는지 확인합니다. 해당된다면 사용할 프로그램을 선택합니다. 허리를 곧게 펴고 앉아 엉덩이에서부터 앞으로 숙입니다.", "로잉 머신을 사용할 때는 세 단계의 동작이 있습니다. 첫 번째 단계는 머신 앞쪽으로 나아가는 구간입니다. 무릎은 굽혀 가슴 쪽에 붙이고, 상체는 바른 자세를 유지하면서 살짝 앞으로 기울입니다. 다음으로 발판을 밀며 다리를 펴고, 손을 상복부까지 당기면서 어깨를 뒤로 조입니다. 허리에 무리가 가지 않도록 주로 다리와 엉덩이 근육을 사용합니다.", "회복 단계는 단순히 팔을 펴고 무릎을 굽혀 몸을 다시 앞으로 가져와 첫 번째 단계로 전환하는 과정입니다."], en: ["To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips.", "There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles.", "The recovery phase simply involves straightening your arms, bending the knees, and bringing your body forward again as you transition back into the first phase."] },
  "어시스트 풀업": { s: "Band_Assisted_Pull-Up/0.jpg", e: "Band_Assisted_Pull-Up/1.jpg", k: ["밴드를 풀업 바 중앙에 감아 조입니다. 여러 종류의 밴드를 사용해 보조 강도를 다르게 조절할 수 있습니다.", "밴드 끝을 아래로 당겨 굽힌 한쪽 무릎을 고리에 넣고, 빠지지 않도록 확실히 고정합니다. 바를 중간에서 넓은 그립으로 잡습니다. 이것이 시작 자세입니다.", "팔꿈치를 굽히며 광배근을 수축시켜 몸을 위로 당깁니다. 팔꿈치는 몸 옆으로 당겨 내립니다. 앞쪽으로 당겨 턱이 바 위로 올라오게 합니다. 몸을 흔들거나 반동을 쓰는 동작은 피합니다.", "잠시 멈춘 뒤 시작 자세로 돌아옵니다."], en: ["Choke the band around the center of the pullup bar. You can use different bands to provide varying levels of assistance.", "Pull the end of the band down, and place one bent knee into the loop, ensuring it won't slip out. Take a medium to wide grip on the bar. This will be your starting position.", "Pull yourself upward by contracting the lats as you flex the elbow. The elbow should be driven to your side. Pull to the front, attempting to get your chin over the bar. Avoid swinging or jerking movements.", "After a brief pause, return to the starting position."] },
  "어시스트 친업": { s: "Chin-Up/0.jpg", e: "Chin-Up/1.jpg", k: ["손바닥이 상체를 향하도록 하고 어깨너비보다 좁은 그립으로 풀업 바를 잡습니다.", "선택한 그립 너비로 바를 잡고 양팔을 앞으로 편 상태에서, 허리를 아래로 살짝 아치를 만들고 가슴을 내밀며 상체를 최대한 곧게 유지합니다. 이것이 시작 자세입니다. 팁: 상체를 최대한 곧게 유지하면 등의 개입을 최소화하면서 이두근 자극을 극대화할 수 있습니다.", "숨을 내쉬며 머리가 풀업 바 높이에 이를 때까지 상체를 당겨 올립니다. 이두근을 사용해 동작을 수행하는 데 집중합니다. 팔꿈치는 몸에 가깝게 유지합니다. 팁: 상체는 공간을 이동하는 동안에도 고정된 상태를 유지하고 팔만 움직여야 합니다. 전완은 바를 잡는 것 외에 다른 일을 해서는 안 됩니다.", "수축된 자세에서 이두근을 1초간 조인 뒤, 팔이 완전히 펴질 때까지 상체를 천천히 시작 자세로 내립니다. 이 구간에서 숨을 들이마십니다.", "정해진 반복 횟수만큼 이 동작을 반복합니다."], en: ["Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.", "As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.", "As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.", "After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.", "Repeat this motion for the prescribed amount of repetitions."] },
  "어시스트 딥스": { s: "Parallel_Bar_Dip/0.jpg", e: "Parallel_Bar_Dip/1.jpg", k: ["평행봉 사이에 섭니다. 양쪽 봉에 손을 하나씩 얹고, 작게 점프해 팔을 완전히 편 시작 자세를 잡습니다.", "팔꿈치를 굽혀 팔이 90도 아래로 내려갈 때까지 몸을 내립니다. 몸을 흔들지 말고 내려가는 내내 바른 자세를 유지합니다.", "팔꿈치를 펴며 동작을 반대로 하여 몸을 다시 시작 자세로 밀어 올립니다.", "원하는 반복 횟수만큼 반복합니다."], en: ["Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out.", "Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.", "Reverse the motion by extending the elbow, pushing yourself back up into the starting position.", "Repeat for the desired number of repetitions."] },
  "하이 로우": { s: "Leverage_High_Row/0.jpg", e: "Leverage_High_Row/1.jpg", k: ["핀에 적절한 무게를 걸고, 위쪽 손잡이에 손이 겨우 닿을 정도로 시트 높이를 조절합니다. 무릎 패드를 조절해 몸이 뜨지 않도록 고정합니다. 손잡이를 오버핸드(엎은) 그립으로 잡습니다. 이것이 시작 자세입니다.", "팔꿈치를 굽히며 견갑골을 모아 손잡이를 상체 쪽으로 당깁니다.", "동작 끝에서 잠시 멈춘 뒤 손잡이를 천천히 시작 자세로 되돌립니다.", "여러 번 반복할 때는 무게를 완전히 스톱까지 내리지 않아 작용 근육에 긴장을 유지합니다."], en: ["Load an appropriate weight onto the pins and adjust the seat height so that you can just reach the handles above you. Adjust the knee pad to help keep you down. Grasp the handles with a pronated grip. This will be your starting position.", "Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.", "Pause at the bottom of the motion, and then slowly return the handles to the starting position.", "For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked."] },
  "로우 로우": { s: "Leverage_Iso_Row/0.jpg", e: "Leverage_Iso_Row/1.jpg", k: ["핀에 적절한 무게를 걸고, 손잡이가 가슴 높이에 오도록 시트 높이를 조절합니다. 손잡이를 뉴트럴(중립) 또는 오버핸드(엎은) 그립으로 잡습니다. 이것이 시작 자세입니다.", "팔꿈치를 굽히며 견갑골을 모아 손잡이를 상체 쪽으로 당깁니다.", "동작 끝에서 잠시 멈춘 뒤 손잡이를 천천히 시작 자세로 되돌립니다. 여러 번 반복할 때는 무게를 완전히 스톱까지 내리지 않아 작용 근육에 긴장을 유지합니다."], en: ["Load an appropriate weight onto the pins and adjust the seat height so that the handles are at chest level. Grasp the handles with either a neutral or pronated grip. This will be your starting position.", "Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.", "Pause at the bottom of the motion, and then slowly return the handles to the starting position. For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked."] },
  "체스트 서포티드 로우": { s: "Lying_T-Bar_Row/0.jpg", e: "Lying_T-Bar_Row/1.jpg", k: ["T바 로우 머신에 원하는 무게를 걸고, 상부 가슴이 패드 맨 위에 오도록 다리 높이를 조절합니다. 팁: 일부 머신은 상부 가슴이 패드 맨 위에 오는 높이가 되도록 알맞은 발판에 올라서는 것만 가능합니다.", "패드에 엎드려 손잡이를 잡습니다. 등의 어느 부위를 강조하고 싶은지에 따라 손바닥이 아래·위·서로 마주보는 위치 중에서 선택할 수 있습니다.", "바를 거치대에서 들어 올려 팔을 앞으로 폅니다. 이것이 시작 자세입니다.", "숨을 내쉬며 천천히 무게를 당겨 올리고 동작 정점에서 등을 조입니다. 팁: 등 근육을 더 잘 쓰기 위해 동작 내내 상완을 상체에 최대한 가깝게 유지합니다. 또한 어느 순간에도 몸을 패드에서 떼지 말고 이두근으로 무게를 들지 않습니다.", "동작 정점에서 1초간 수축한 뒤, 숨을 들이마시며 천천히 시작 자세로 내려갑니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Load up the T-bar Row Machine with the desired weight and adjust the leg height so that your upper chest is at the top of the pad. Tip: In some machines all you can do is stand on the appropriate step that allows you to be at a height that has the upper chest at the top of the pad.", "Lay face down on the pad and grab the handles. You can either use a palms down, palms up, or palms in position depending on what part of your back you want to emphasize.", "Lift the bar off the rack and extend your arms in front of you. This will be your starting position.", "As you exhale slowly pull the weight up and squeeze your back at the top of the movement. Tip: Keep the upper arms as close to the torso as possible throughout the movement in order to better engage the back muscles. Also, do not lift your body off of the pad at any time and refrain from using the biceps to lift the weight.", "After a second contraction at the top of the movement, as you inhale, slowly go back down to the starting position.", "Repeat for the recommended amount of repetitions."] },
  "인버티드 로우": { s: "Inverted_Row/0.jpg", e: "Inverted_Row/1.jpg", k: ["랙에 바를 대략 허리 높이로 설치합니다. 스미스 머신을 사용해도 됩니다.", "바를 어깨너비보다 넓게 잡고 바 아래에 매달리는 자세를 잡습니다. 몸은 곧게 펴고 뒤꿈치는 바닥에 대며 팔은 완전히 편 상태여야 합니다. 이것이 시작 자세입니다.", "팔꿈치를 굽히며 가슴을 바 쪽으로 당깁니다. 동작을 수행하며 견갑골을 모읍니다.", "동작 정점에서 잠시 멈춘 뒤 시작 자세로 돌아옵니다.", "원하는 반복 횟수만큼 반복합니다."], en: ["Position a bar in a rack to about waist height. You can also use a smith machine.", "Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.", "Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.", "Pause at the top of the motion, and return yourself to the start position.", "Repeat for the desired number of repetitions."] },
  "원암 랫풀다운": { s: "One_Arm_Lat_Pulldown/0.jpg", e: "One_Arm_Lat_Pulldown/1.jpg", k: ["적절한 무게를 선택하고 무릎 패드를 조절해 몸이 뜨지 않도록 고정합니다. 손잡이를 오버핸드(엎은) 그립으로 잡습니다. 이것이 시작 자세입니다.", "팔꿈치를 굽히며 팔꿈치를 옆구리 쪽으로 조여 손잡이를 아래로 당깁니다.", "동작 끝에서 잠시 멈춘 뒤 손잡이를 천천히 시작 자세로 되돌립니다.", "여러 번 반복할 때는 무게를 완전히 되돌리지 않아 작용 근육에 긴장을 유지합니다."], en: ["Select an appropriate weight and adjust the knee pad to help keep you down. Grasp the handle with a pronated grip. This will be your starting position.", "Pull the handle down, squeezing your elbow to your side as you flex the elbow.", "Pause at the bottom of the motion, and then slowly return the handle to the starting position.", "For multiple repetitions, avoid completely returning the weight to keep tension on the muscles being worked."] },
  "덤벨 풀오버": { s: "Bent-Arm_Dumbbell_Pullover/0.jpg", e: "Bent-Arm_Dumbbell_Pullover/1.jpg", k: ["덤벨 하나를 평벤치 위에 세워 둡니다.", "덤벨이 벤치 위쪽에 안정적으로 놓여 있도록 유지하면서, 어깨만 벤치 표면에 닿도록 벤치와 수직으로(십자 모양처럼 상체를 가로질러) 눕습니다. 엉덩이는 벤치보다 낮게 두고 다리는 굽혀 발을 바닥에 단단히 붙입니다. 머리도 벤치 밖으로 나오게 합니다.", "양손으로 덤벨을 잡고 팔을 살짝 굽힌 채 가슴 바로 위로 곧게 듭니다. 양 손바닥은 덤벨 한쪽 원판의 아랫면을 받치듯 눌러야 합니다. 이것이 시작 자세입니다. 주의: 이 운동에 사용하는 덤벨이 확실히 고정되어 있는지 항상 확인하세요. 원판이 헐거운 덤벨을 쓰면 덤벨이 분리되어 얼굴 위로 떨어질 수 있습니다.", "팔을 굽힌 자세로 잠근 채, 숨을 들이마시며 가슴에 늘어나는 느낌이 들 때까지 무게를 머리 뒤로 호를 그리며 천천히 내립니다.", "그 지점에서 무게를 내렸던 호를 따라 덤벨을 시작 자세로 되가져오며 숨을 내쉽니다.", "시작 위치에서 1초간 무게를 유지한 뒤 정해진 반복 횟수만큼 동작을 반복합니다."], en: ["Place a dumbbell standing up on a flat bench.", "Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.", "Grasp the dumbbell with both hands and hold it straight over your chest with a bend in your arms. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position. Caution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.", "While keeping your arms locked in the bent arm position, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.", "At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.", "Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions."] },
  "랜드마인 프레스": { s: "Landmine_Linear_Jammer/0.jpg", e: "Landmine_Linear_Jammer/1.jpg", k: ["바를 랜드마인 거치대에 끼우거나, 없다면 모서리에 단단히 고정합니다. 바에 적절한 무게를 걸고 손잡이 부착물을 바에 끼웁니다.", "바를 바닥에서 들어 올려 손잡이를 어깨로 가져옵니다. 이것이 시작 자세입니다.", "운동선수 자세로, 팔은 굽힌 채 엉덩이를 굽히고 뒤로 빼며 스쿼트합니다.", "엉덩이, 무릎, 발목을 힘차게 펴는 동시에 팔꿈치를 펴 팔을 곧게 뻗으며 동작을 반대로 합니다. 이 동작은 폭발적으로 수행하여 스쿼트에서 완전 신전까지 최대한 힘차게 올라와야 합니다.", "시작 자세로 돌아옵니다."], en: ["Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar.", "Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position.", "In an athletic stance, squat by flexing your hips and setting your hips back, keeping your arms flexed.", "Reverse the motion by powerfully extending through the hips, knees, and ankles, while also extending the elbows to straighten the arms. This movement should be done explosively, coming out of the squat to full extension as powerfully as possible.", "Return to the starting position."] },
  "케이블 리어 델트 플라이": { s: "Cable_Rear_Delt_Fly/0.jpg", e: "Cable_Rear_Delt_Fly/1.jpg", k: ["도르래를 적절한 높이로 조절하고 무게를 설정합니다. 도르래는 머리 위쪽에 있어야 합니다.", "오른손으로 왼쪽 도르래를, 왼손으로 오른쪽 도르래를 잡아 몸 앞에서 교차시킵니다. 이것이 시작 자세입니다.", "팔을 곧게 편 상태를 유지하며 팔을 뒤·바깥쪽으로 벌려 동작을 시작합니다.", "동작 끝에서 잠시 멈춘 뒤 손잡이를 시작 자세로 되돌립니다."], en: ["Adjust the pulleys to the appropriate height and adjust the weight. The pulleys should be above your head.", "Grab the left pulley with your right hand and the right pulley with your left hand, crossing them in front of you. This will be your starting position.", "Initiate the movement by moving your arms back and outward, keeping your arms straight as you execute the movement.", "Pause at the end of the motion before returning the handles to the start position."] },
  "시시 스쿼트": { s: "Weighted_Sissy_Squat/0.jpg", e: "Weighted_Sissy_Squat/1.jpg", k: ["발을 어깨너비로 벌리고 발끝을 든 채 똑바로 서서, 한 손으로 스쿼트 랙 기둥을 잡고 반대 팔로는 원판을 가슴 위에 얹어 잡습니다. 이것이 시작 자세입니다.", "한 팔로 몸을 지탱하면서 무릎을 굽히고 골반과 무릎을 앞으로 내밀며 상체를 천천히 바닥 쪽으로 내립니다. 내려가면서 숨을 들이마시고 허벅지와 종아리가 거의 90도 각도를 이룰 때 멈춥니다. 늘어난 자세를 1초간 유지합니다.", "1초간 멈춘 뒤 허벅지 근육을 사용해 상체를 시작 자세로 되올립니다. 올라오면서 숨을 내쉽니다.", "권장 횟수만큼 반복합니다."], en: ["Standing upright, with feet at shoulder width and toes raised, use one hand to hold onto the beams of a squat rack and the opposite arm to hold a plate on top of your chest. This is your starting position.", "As you use one arm to hold yourself, bend at the knees and slowly lower your torso toward the ground by bringing your pelvis and knees forward. Inhale as you go down and stop when your upper and lower legs almost create a 90-degree angle. Hold the stretch position for a second.", "After your one second hold, use your thigh muscles to bring your torso back up to the starting position. Exhale as you move up.", "Repeat for the recommended amount of times."] },
  "힙 어덕션 머신": { s: "Thigh_Adductor/0.jpg", e: "Thigh_Adductor/1.jpg", k: ["먼저 어덕터(모음) 머신에 앉아 편안한 무게를 선택합니다. 다리를 머신의 다리 패드에 알맞게 위치시킨 뒤 양쪽 손잡이를 잡습니다. 상체 전체(허리 위로)는 고정된 상태여야 합니다. 이것이 시작 자세입니다.", "숨을 내쉬며 다리로 머신을 천천히 밀어 양다리를 서로 모읍니다.", "1초간 수축을 느낀 뒤 숨을 들이마시며 다리를 시작 자세로 되돌리기 시작합니다. 참고: 부상을 예방하기 위해 상체를 고정한 상태로 유지하고 빠르게 반동을 쓰는 동작을 피하세요.", "권장 반복 횟수만큼 반복합니다."], en: ["To begin, sit down on the adductor machine and select a weight you are comfortable with. When your legs are positioned properly on the leg pads of the machine, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.", "Slowly press against the machine with your legs to move them towards each other while exhaling.", "Feel the contraction for a second and begin to move your legs back to the starting position while breathing in. Note: Remember to keep your upper body stationary and avoid fast jerking motions in order to prevent any injuries from occurring.", "Repeat for the recommended amount of repetitions."] },
  "스미스 힙 쓰러스트": { s: "Barbell_Hip_Thrust/0.jpg", e: "Barbell_Hip_Thrust/1.jpg", k: ["벤치를 바로 뒤에 둔 채 바닥에 앉아 시작합니다. 무게를 건 바벨을 다리 위에 놓습니다. 두꺼운 바를 쓰거나 바에 패드를 대면 이 운동으로 인한 불편함을 크게 줄일 수 있습니다.", "바를 굴려 엉덩이 바로 위에 오게 하고, 견갑골이 벤치 윗부분 근처에 오도록 벤치에 기댑니다.", "발로 밀며 엉덩이를 수직으로 펴 바를 밀어 올려 동작을 시작합니다. 체중은 견갑골과 발로 지탱해야 합니다. 최대한 멀리 편 뒤 동작을 반대로 하여 시작 자세로 돌아옵니다."], en: ["Begin seated on the ground with a bench directly behind you. Have a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise.", "Roll the bar so that it is directly above your hips, and lean back against the bench so that your shoulder blades are near the top of it.", "Begin the movement by driving through your feet, extending your hips vertically through the bar. Your weight should be supported by your shoulder blades and your feet. Extend as far as possible, then reverse the motion to return to the starting position."] },
  "JM 프레스": { s: "JM_Press/0.jpg", e: "JM_Press/1.jpg", k: ["클로즈 그립 벤치프레스와 같은 방식으로 운동을 시작합니다. 평벤치에 누워 팔꿈치를 붙인 채 바벨을 팔 길이만큼(완전히 편 상태) 듭니다. 다만 팔을 상체와 수직으로 두는 대신, 바가 상부 가슴 바로 위 일직선상에 오도록 합니다. 이것이 시작 자세입니다.", "이제 완전히 편 자세에서 시작해 라잉 트라이셉스 익스텐션을 하듯 바를 아래로 내립니다. 이 동작을 하면서 숨을 들이마십니다. 중간 지점에 도달하면 상완을 다리 쪽으로 움직여 상체와 수직이 될 때까지 바를 약 2.5센티미터(1인치) 정도 뒤로 굴립니다. 팁: 상완을 앞으로 가져오는 동안 팔꿈치 굽힘 각도를 일정하게 유지하세요.", "숨을 내쉬며 삼두근을 사용해 클로즈 그립 벤치프레스를 하듯 바를 다시 밀어 올립니다.", "이제 시작 자세로 돌아가 다시 시작합니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Start the exercise the same way you would a close grip bench press. You will lie on a flat bench while holding a barbell at arms length (fully extended) with the elbows in. However, instead of having the arms perpendicular to the torso, make sure the bar is set in a direct line above the upper chest. This will be your starting position.", "Now beginning from a fully extended position lower the bar down as if performing a lying triceps extension. Inhale as you perform this movement. When you reach the half way point, let the bar roll back about one inch by moving the upper arms towards your legs until they are perpendicular to the torso. Tip: Keep the bend at the elbows constant as you bring the upper arms forward.", "As you exhale, press the bar back up by using the triceps to perform a close grip bench press.", "Now go back to the starting position and start over.", "Repeat for the recommended amount of repetitions."] },
  "딥 머신": { s: "Dip_Machine/0.jpg", e: "Dip_Machine/1.jpg", k: ["딥 머신에 안정적으로 앉아 무게를 선택하고 손잡이를 단단히 잡습니다.", "이제 삼두근에 집중이 가도록 팔꿈치를 옆구리에 붙입니다. 팔꿈치는 90도로 굽혀야 합니다.", "삼두근을 수축하면서 숨을 내쉬며 팔을 아래로 폅니다. 팁: 동작 맨 아래에서 삼두근에 긴장을 유지하기 위해 팔을 완전히 펴지 말고 약간 굽힌 상태를 유지하는 데 집중하세요.", "이제 숨을 들이마시며 천천히 팔을 시작 자세로 되올립니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Sit securely in a dip machine, select the weight and firmly grasp the handles.", "Now keep your elbows in at your sides in order to place emphasis on the triceps. The elbows should be bent at a 90 degree angle.", "As you contract the triceps, extend your arms downwards as you exhale. Tip: At the bottom of the movement, focus on keeping a little bend in your arms to keep tension on the triceps muscle.", "Now slowly let your arms come back up to the starting position as you inhale.", "Repeat for the recommended amount of repetitions."] },
  "케이블 해머 컬": { s: "Cable_Hammer_Curls_-_Rope_Attachment/0.jpg", e: "Cable_Hammer_Curls_-_Rope_Attachment/1.jpg", k: ["로프 부착물을 낮은 도르래에 연결하고 머신을 마주 본 채 약 30센티미터(12인치) 떨어져 섭니다.", "로프를 뉴트럴(손바닥이 마주보는) 그립으로 잡고, 허리의 자연스러운 아치와 상체를 고정한 채 똑바로 섭니다.", "팔꿈치를 옆구리에 붙이고 동작 내내 그 위치에 고정합니다. 팁: 전완만 움직이고 상완은 움직이지 않아야 합니다. 이것이 시작 자세입니다.", "이두근을 사용해 숨을 내쉬며 이두근이 전완에 닿을 때까지 팔을 당겨 올립니다. 팁: 팔꿈치를 붙인 채 상완을 고정한 상태를 유지하세요.", "이두근을 조이며 1초간 수축한 뒤 천천히 무게를 원래 위치로 되돌리기 시작합니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it.", "Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary.", "Put your elbows in by your side and keep them there stationary during the entire movement. Tip: Only the forearms should move; not your upper arms. This will be your starting position.", "Using your biceps, pull your arms up as you exhale until your biceps touch your forearms. Tip: Remember to keep the elbows in and your upper arms stationary.", "After a 1 second contraction where you squeeze your biceps, slowly start to bring the weight back to the original position.", "Repeat for the recommended amount of repetitions."] },
  "라잉 레그 레이즈": { s: "Flat_Bench_Lying_Leg_Raise/0.jpg", e: "Flat_Bench_Lying_Leg_Raise/1.jpg", k: ["등을 벤치에 편평하게 대고 눕고, 다리는 벤치 끝 밖으로 앞으로 편 상태로 둡니다.", "손은 손바닥을 아래로 하여 엉덩이 밑에 넣거나, 벤치 양옆을 잡습니다. 이것이 시작 자세입니다.", "다리를 최대한 곧게 편 상태로, 무릎을 살짝 굽히되 고정한 채 다리가 바닥과 90도 각도를 이룰 때까지 들어 올립니다. 이 구간에서 숨을 내쉬고 정점에서 1초간 수축을 유지합니다.", "이제 숨을 들이마시며 다리를 천천히 시작 자세로 내립니다."], en: ["Lie with your back flat on a bench and your legs extended in front of you off the end.", "Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position.", "As you keep your legs extended, straight as possible with your knees slightly bent but locked raise your legs until they make a 90-degree angle with the floor. Exhale as you perform this portion of the movement and hold the contraction at the top for a second.", "Now, as you inhale, slowly lower your legs back down to the starting position."] },
  "케이블 우드촙": { s: "Standing_Cable_Wood_Chop/0.jpg", e: "Standing_Cable_Wood_Chop/1.jpg", k: ["일반 손잡이를 케이블 타워에 연결하고 케이블을 가장 높은 도르래 위치로 옮깁니다.", "케이블을 옆으로 두고 서서 한 손으로 손잡이를 잡고 타워에서 멀어집니다. 도르래에서 대략 팔 하나 길이만큼 떨어져 케이블에 무게 긴장이 걸린 상태여야 합니다. 뻗은 팔은 케이블과 일직선을 이루어야 합니다.", "발을 어깨너비로 벌리고, 다른 손을 위로 뻗어 양손으로 손잡이를 잡습니다. 팔은 여전히 완전히 편 상태여야 합니다.", "한 동작으로, 상체를 회전시키면서 손잡이를 아래로 그리고 몸을 가로질러 앞쪽 무릎까지 당깁니다.", "축이 되는 뒷발을 회전시키고 무릎을 굽혀 전체 가동 범위를 확보하는 동안 허리와 팔은 곧게, 코어는 단단히 유지합니다.", "자세와 곧게 편 팔을 유지합니다. 천천히 통제된 동작으로 중립 위치로 돌아옵니다.", "실패 지점까지 반복합니다.", "그런 다음 자세를 바꿔 반대쪽에서 같은 동작을 반복합니다."], en: ["Connect a standard handle to a tower, and move the cable to the highest pulley position.", "With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm's length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable.", "With your feet positioned shoulder width apart, reach upward with your other hand and grab the handle with both hands. Your arms should still be fully extended.", "In one motion, pull the handle down and across your body to your front knee while rotating your torso.", "Keep your back and arms straight and core tight while you pivot your back foot and bend your knees to get a full range of motion.", "Maintain your stance and straight arms. Return to the neutral position in a slow and controlled manner.", "Repeat to failure.", "Then, reposition and repeat the same series of movements on the opposite side."] },
  "앱 크런치 머신": { s: "Ab_Crunch_Machine/0.jpg", e: "Ab_Crunch_Machine/1.jpg", k: ["가벼운 저항을 선택하고 앱 머신에 앉아 발을 제공된 패드 아래에 넣고 위쪽 손잡이를 잡습니다. 제공된 패드에 삼두근을 얹은 채 팔은 90도로 굽혀야 합니다. 이것이 시작 자세입니다.", "동시에 상체를 크런치하면서 다리를 들어 올리기 시작합니다. 이 동작을 하면서 숨을 내쉽니다. 팁: 반드시 천천히 통제된 동작을 사용하세요. 다리와 발은 이완한 채 복근을 사용해 무게를 움직이는 데 집중합니다.", "1초간 멈춘 뒤 숨을 들이마시며 천천히 시작 자세로 돌아옵니다.", "정해진 반복 횟수만큼 동작을 반복합니다."], en: ["Select a light resistance and sit down on the ab machine placing your feet under the pads provided and grabbing the top handles. Your arms should be bent at a 90 degree angle as you rest the triceps on the pads provided. This will be your starting position.", "At the same time, begin to lift the legs up as you crunch your upper torso. Breathe out as you perform this movement. Tip: Be sure to use a slow and controlled motion. Concentrate on using your abs to move the weight while relaxing your legs and feet.", "After a second pause, slowly return to the starting position as you breathe in.", "Repeat the movement for the prescribed amount of repetitions."] },
  "케이블 슈러그": { s: "Cable_Shrugs/0.jpg", e: "Cable_Shrugs/1.jpg", k: ["낮은 도르래에 연결된 케이블 바 부착물을 어깨너비 또는 그보다 약간 넓은 오버핸드(손바닥이 아래를 향하는) 그립으로 잡습니다.", "도르래 가까이에 똑바로 서서 팔을 앞으로 편 채 바를 잡습니다. 이것이 시작 자세입니다.", "숨을 내쉬며 어깨를 최대한 높이 들어 올려 바를 듭니다. 정점에서 1초간 수축을 유지합니다. 팁: 팔은 항상 편 상태를 유지해야 합니다. 이두근으로 바를 드는 것을 삼가세요. 오직 어깨만 위아래로 움직여야 합니다.", "바를 원래 위치로 내립니다.", "권장 반복 횟수만큼 반복합니다."], en: ["Grasp a cable bar attachment that is attached to a low pulley with a shoulder width or slightly wider overhand (palms facing down) grip.", "Stand erect close to the pulley with your arms extended in front of you holding the bar. This will be your starting position.", "Lift the bar by elevating the shoulders as high as possible as you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the bar. Only the shoulders should be moving up and down.", "Lower the bar back to the original position.", "Repeat for the recommended amount of repetitions."] },
};
